import { Client, Account, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your region/endpoint
    .setProject('YOUR_PROJECT_ID'); // Replace with your project ID

const account = new Account(client);

// Email/Password Signup
async function signup(email: string, password: string, name?: string) {
    try {
        const user = await account.create(
            ID.unique(),
            email,
            password,
            name
        );
        console.log('User created:', user);
        return user;
    } catch (error) {
        console.error('Signup failed:', error);
        throw error;
    }
}

// Email/Password Login
async function login(email: string, password: string) {
    try {
        const session = await account.createEmailPasswordSession(email, password);
        console.log('Logged in:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error);
        throw error;
    }
}

// Usage example
// await signup('user@example.com', 'password123', 'John Doe');
// await login('user@example.com', 'password123');
```

**Installation:** `npm install appwrite`

**Notes:**
- Replace `YOUR_PROJECT_ID` and endpoint.
- Signup creates a new user account.
- Login creates an active session (persists automatically in browser).
- Handle errors (e.g., duplicate email) with try-catch.
- Optional: Get current user with `account.get()` or logout with `account.deleteSession('current')`.

