const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Use your region if self-hosted
    .setProject('YOUR_PROJECT_ID')
    .setKey('YOUR_API_KEY'); // Server-side only: requires API key with `databases.write` scope

