const collectionId = ID.unique();
await tablesDB.createTable({
    databaseId,
    tableId: collectionId,
    name: 'tasks',
    columns: [
        { key: 'title', type: 'varchar', size: 255, required: true },
        { key: 'completed', type: 'boolean', required: false, default: false },
        { key: 'dueDate', type: 'datetime', required: false }
    ],
    // Default document permissions (adjust as needed)
    permissions: [
        Permission.read(Role.any()),
        Permission.create(Role.any()),
        Permission.update(Role.user('USER_ID')), // Replace with actual user/team
        Permission.delete(Role.user('USER_ID'))
    ]
});

// 3. Insert a document
const taskId = ID.unique();
const task = await tablesDB.createRow({
    databaseId,
    tableId: collectionId,
    rowId: taskId,
    data: {
        title: 'Learn Appwrite',
        completed: false,
        dueDate: '2024-12-31T23:59:59.000Z'
    }
});

console.log('Created:', { databaseId, collectionId, taskId, task });
```

**Notes:**
- **Web SDK limitation**: Client-side Web SDK (`import { ... } from 'appwrite'`) **cannot** create databases/collections (requires API key/server-side). Use Node.js server or Appwrite Console for setup, then Web SDK for documents.
- Replace placeholders (`YOUR_PROJECT_ID`, `YOUR_API_KEY`, `USER_ID`).
- Run in Node.js: `npm install node-appwrite`.
- Collection permissions set defaults for new documents; override per-document if needed.
- Indexes/auto-rules optional for basic setup.

