                'write("users")' // Only authenticated users can upload
            ],
            fileSecurity: true, // Enable file-level permissions
            maximumFileSize: 10 * 1024 * 1024, // 10MB max
            allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp'],
            encryption: false,
            antivirus: true // Scan uploaded files for viruses
        });

        console.log('Bucket created:', bucket.$id);
