// ============================================
// CLIENT-SIDE: Upload file and get preview URL
// ============================================

import { Client, Storage, ID, Permission, Role } from 'appwrite';

// Client-side setup
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID'); // Replace with your project ID

const storage = new Storage(client);

// Example: Upload an image file with permissions
async function uploadImageFile(fileInput: HTMLInputElement, userId: string) {
    if (!fileInput.files || fileInput.files.length === 0) {
        throw new Error('No file selected');
    }

    const file = fileInput.files[0];
    const bucketId = 'YOUR_BUCKET_ID'; // Replace with your bucket ID

    try {
        // Upload file with permissions
        const uploadedFile = await storage.createFile({
            bucketId,
            fileId: ID.unique(),
            file,
            permissions: [
                Permission.read(Role.any()), // Public read access
                Permission.read(Role.user(userId)), // Owner can read
                Permission.update(Role.user(userId)), // Owner can update
                Permission.delete(Role.user(userId)), // Owner can delete
                Permission.read(Role.team('team-id')), // Team members can read (optional)
            ]
        });

        console.log('File uploaded:', uploadedFile.$id);

        // Get preview URL for the image
        const previewUrl = storage.getFilePreview({
            bucketId,
            fileId: uploadedFile.$id,
            width: 300, // Resize to 300px width
            height: 300, // Resize to 300px height
            gravity: 'center', // Center crop
            quality: 85, // JPEG quality (1-100)
            borderWidth: 2, // Add 2px border
            borderColor: 'ffffff', // White border
            borderRadius: 10, // Rounded corners (10px)
            opacity: 1, // Full opacity
            rotation: 0, // No rotation
            background: '000000', // Black background for transparent images
            output: 'webp' // Convert to WebP format
        });

        console.log('Preview URL:', previewUrl);

        // You can use this URL directly in an <img> tag
       img src={previewUrl} alt="Image preview" />

        return {
            file: uploadedFile,
            previewUrl,
            downloadUrl: storage.getFileDownload({ bucketId, fileId: uploadedFile.$id })
        };
    } catch (error) {
        console.error('Error uploading file:', error);
        throw error;
    }
}

// Example: Get file metadata and preview URL for existing file
async function getFilePreview(bucketId: string, fileId: string) {
    try {
        // Get file metadata
        const file = await storage.getFile({ bucketId, fileId });
        console.log('File metadata:', file);

        // Generate preview URL with different options
        const previewUrl = storage.getFilePreview({
            bucketId,
            fileId,
            width: 400,
            height: 400,
            gravity: 'top', // Crop from top
            quality: 90,
            output: 'jpg' // Force JPEG output
        });

        return {
            file,
