// Example: Update file permissions
async function updateFilePermissions(bucketId: string, fileId: string, userId: string) {
    try {
        await storage.updateFile({
            bucketId,
            fileId,
            permissions: [
                Permission.read(Role.any()), // Public read
                Permission.read(Role.user(userId)), // Owner read
                Permission.update(Role.user(userId)), // Owner update
                Permission.delete(Role.user(userId)), // Owner delete
                // Remove public write access for security
            ]
        });

        console.log('File permissions updated');
    } catch (error) {
        console.error('Error updating permissions:', error);
        throw error;
    }
}

