/*
1. BUCKET CREATION:
   - Requires server-side/admin access with API key
   - Typically done once during app setup
   - Configure bucket permissions, file size limits, allowed extensions

2. FILE UPLOAD PERMISSIONS:
   - Always set appropriate permissions for security
   - Use Role.any() cautiously - makes files publicly accessible
   - Consider using Role.user(userId) for owner-only access
   - Use Role.team(teamId) for team-based access

3. PREVIEW URLS:
   - getFilePreview() returns a URL string, not a Promise
   - The URL can be used directly in <img src="">
   - Supports various image transformations (resize, crop, format conversion)
   - Preview URLs are publicly accessible if file has read("any") permission

4. SECURITY BEST PRACTICES:
   - Always validate file types and sizes client-side AND server-side
   - Use antivirus scanning (enabled in bucket settings)
   - Set appropriate file-level permissions
   - Never allow public write access (Permission.write(Role.any()))
   - Consider using signed URLs for sensitive files

5. ERROR HANDLING:
   - Always wrap storage operations in try-catch blocks
   - Handle rate limiting (429 errors)
   - Check for permission errors (403)
*/
```

## Key Points:

1. **Bucket Creation**: Server-side operation requiring API key. Configure security settings, file size limits, and allowed extensions.

2. **File Upload**: Client-side operation with permission configuration. Use `Permission` and `Role` helpers to control access.

3. **Preview URL**: Use `storage.getFilePreview()` with transformation options (resize, crop, format conversion).

4. **Permissions**: 
   - `Permission.read(Role.any())` - Public read access
   - `Permission.read(Role.user(userId))` - Owner read access
   - `Permission.update(Role.user(userId))` - Owner update access
   - `Permission.delete(Role.user(userId))` - Owner delete access

5. **Security**: Always validate files, use antivirus scanning, and avoid public write permissions.

The code provides complete examples for both server-side bucket setup and client-side file operations with proper permission configuration.

```typescript
import { Client, Realtime, Channel, Models } from 'appwrite';

// Initialize the Appwrite client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Replace with your endpoint
    .setProject('[PROJECT_ID]'); // Replace with your project ID

const realtime = new Realtime(client);

// Subscribe to both document changes and file uploads simultaneously
async function subscribeToRealtimeEvents() {
    try {
        // Subscribe to document changes in a specific table
        const documentSubscription = await realtime.subscribe(
            Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
            (response) => {
                handleDocumentEvent(response);
            }
        );

        // Subscribe to file uploads in a specific bucket
        const fileSubscription = await realtime.subscribe(
            Channel.bucket('[BUCKET_ID]').file(),
            (response) => {
                handleFileEvent(response);
            }
        );

        console.log('Subscribed to realtime events');

        // Return subscriptions for cleanup
        return { documentSubscription, fileSubscription };
    } catch (error) {
        console.error('Failed to subscribe to realtime events:', error);
        throw error;
    }
}

// Handle document events differently based on event type
function handleDocumentEvent(response: Models.RealtimeResponse) {
    const { events, payload, channels, timestamp } = response;

    console.log('📄 Document Event:', {
        events,
        timestamp,
        channels
    });

    // Check which type of document event occurred
    events.forEach(event => {
        if (event.includes('.create')) {
            console.log('📝 New document created:', payload);
            // Handle document creation
            onDocumentCreated(payload);
        } else if (event.includes('.update')) {
            console.log('✏️ Document updated:', payload);
            // Handle document update
            onDocumentUpdated(payload);
        } else if (event.includes('.delete')) {
            console.log('🗑️ Document deleted:', payload);
            // Handle document deletion
            onDocumentDeleted(payload);
        }
    });
}

// Handle file events differently based on event type
function handleFileEvent(response: Models.RealtimeResponse) {
    const { events, payload, channels, timestamp } = response;

    console.log('📁 File Event:', {
        events,
        timestamp,
        channels
    });

    // Check which type of file event occurred
    events.forEach(event => {
        if (event.includes('.create')) {
            console.log('📤 New file uploaded:', payload);
            // Handle file upload
            onFileUploaded(payload);
        } else if (event.includes('.update')) {
            console.log('🔄 File metadata updated:', payload);
            // Handle file update
            onFileUpdated(payload);
        } else if (event.includes('.delete')) {
            console.log('🗑️ File deleted:', payload);
            // Handle file deletion
            onFileDeleted(payload);
        }
    });
}

// Document event handlers
function onDocumentCreated(document: Models.Document) {
    // Your custom logic for document creation
    console.log('Handling document creation:', document.$id);
    // Example: Update UI, send notification, etc.
}

function onDocumentUpdated(document: Models.Document) {
    // Your custom logic for document update
    console.log('Handling document update:', document.$id);
    // Example: Refresh UI, update cache, etc.
}

function onDocumentDeleted(document: Models.Document) {
    // Your custom logic for document deletion
    console.log('Handling document deletion:', document.$id);
    // Example: Remove from UI, cleanup related data, etc.
}

// File event handlers
function onFileUploaded(file: Models.File) {
    // Your custom logic for file upload
    console.log('Handling file upload:', file.$id, file.name);
    // Example: Process file, generate thumbnails, update UI, etc.
}

function onFileUpdated(file: Models.File) {
    // Your custom logic for file update
    console.log('Handling file update:', file.$id);
    // Example: Update file metadata in UI, etc.
}

function onFileDeleted(file: Models.File) {
    // Your custom logic for file deletion
    console.log('Handling file deletion:', file.$id);
    // Example: Remove file from UI, cleanup storage, etc.
}

// Cleanup function to unsubscribe
async function unsubscribeFromEvents(subscriptions: any) {
    try {
        if (subscriptions.documentSubscription) {
            await subscriptions.documentSubscription.close();
            console.log('Unsubscribed from document events');
        }

        if (subscriptions.fileSubscription) {
            await subscriptions.fileSubscription.close();
            console.log('Unsubscribed from file events');
        }
    } catch (error) {
        console.error('Error unsubscribing:', error);
    }
}

// Usage example
async function main() {
    // Subscribe to events
    const subscriptions = await subscribeToRealtimeEvents();

    // To unsubscribe later (e.g., when component unmounts or app closes)
    // await unsubscribeFromEvents(subscriptions);
}

// Alternative: Subscribe to multiple channels with a single callback
// and differentiate inside the handler
async function subscribeWithSingleCallback() {
    const subscription = await realtime.subscribe([
        Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
        Channel.bucket('[BUCKET_ID]').file(),
    ], (response) => {
        // Check which channel the event came from
        const { channels } = response;

        if (channels.some(channel => channel.includes('tablesdb'))) {
            handleDocumentEvent(response);
        } else if (channels.some(channel => channel.includes('bucket'))) {
            handleFileEvent(response);
        }
    });

    return subscription;
}

// Run the example
main().catch(console.error);
```

## Key Points:

1. **Simultaneous Subscriptions**: The code subscribes to both document changes and file uploads using separate subscriptions for clear separation.

2. **Different Event Handling**: 
   - Document events are handled by `handleDocumentEvent()` which distinguishes between create, update, and delete events
   - File events are handled by `handleFileEvent()` which distinguishes between upload, update, and delete events

3. **Custom Handlers**: Each event type has its own handler function (`onDocumentCreated`, `onFileUploaded`, etc.) where you can implement your specific business logic.

4. **Cleanup**: The `unsubscribeFromEvents()` function properly closes subscriptions when they're no longer needed.

5. **Alternative Approach**: The `subscribeWithSingleCallback()` function shows how to subscribe to multiple channels with a single callback and differentiate between them inside the handler.

## Replace Placeholders:
- `[PROJECT_ID]`: Your Appwrite project ID
- `[DATABASE_ID]`: Your database ID
- `[TABLE_ID]`: Your table/collection ID  
- `[BUCKET_ID]`: Your storage bucket ID

This pattern allows you to handle realtime updates for different resource types with distinct logic while maintaining clean, maintainable code.

Here's a single `client.subscribe()` call that listens to both a database collection's documents and a storage bucket's files:

```typescript
import { Realtime, Channel } from 'appwrite';

const realtime = new Realtime(client);

const subscription = await realtime.subscribe([
    Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
    Channel.bucket('[BUCKET_ID]').file(),
], (response) => {
    console.log('Event:', response.events);
    console.log('Payload:', response.payload);
    console.log('Channels matched:', response.channels);
    console.log('Timestamp:', response.timestamp);
});
```

## Exact Channel Strings:

1. **Database collection documents**: `tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows`
   - Constructed with: `Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row()`
   - Listens to all CRUD operations (create, update, delete) on any row in the specified table

2. **Storage bucket files**: `buckets.[BUCKET_ID].files`
   - Constructed with: `Channel.bucket('[BUCKET_ID]').file()`
   - Listens to all file operations (create, update, delete) in the specified bucket

## Important Notes:

- Replace `[DATABASE_ID]`, `[TABLE_ID]`, and `[BUCKET_ID]` with your actual resource IDs
- The callback receives a `response` object containing:
  - `events`: Array of event strings (e.g., `['tablesdb.*.tables.*.rows.*.create']`)
  - `payload`: The affected resource (row or file object)
  - `channels`: Channels that matched the event
  - `timestamp`: ISO 8601 timestamp of the event
- To unsubscribe: `await subscription.close()`
- For more granular subscriptions:
  - Specific row: `Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row('[ROW_ID]')`
  - Specific file: `Channel.bucket('[BUCKET_ID]').file('[FILE_ID]')`

This single subscription will trigger the callback for any changes to rows in your database table OR files in your storage bucket.

Here's the complete code to implement email/password signup and login using the Appwrite Web SDK:

## Installation

```bash
npm install appwrite
```

## Setup and Authentication Code

```typescript
import { Client, Account, ID } from 'appwrite';

// 1. Set up the client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('[YOUR_PROJECT_ID]');            // Your project ID

// 2. Create Account service instance
const account = new Account(client);

// 3. Email/Password Signup
async function signup(email: string, password: string, name: string) {
    try {
        const user = await account.create({
            userId: ID.unique(),
            email: email,
            password: password,
            name: name
        });

        console.log('Signup successful:', user);
        return user;
    } catch (error) {
        console.error('Signup failed:', error);
        throw error;
    }
}

// 4. Email/Password Login (create session)
async function login(email: string, password: string) {
    try {
        const session = await account.createEmailPasswordSession({
            email: email,
            password: password
        });

        console.log('Login successful:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error);
        throw error;
    }
}

// 5. Get current authenticated user
async function getCurrentUser() {
    try {
        const user = await account.get();
        console.log('Current user:', user);
        return user;
    } catch (error) {
        console.error('No authenticated user:', error);
        throw error;
    }
}

// 6. Logout (delete session)
async function logout() {
    try {
        await account.deleteSession({ sessionId: 'current' });
        console.log('Logout successful');
    } catch (error) {
        console.error('Logout failed:', error);
        throw error;
    }
}

// Usage Example
async function main() {
    // Signup a new user
    await signup('user@example.com', 'password123', 'John Doe');

    // Login the user
    await login('user@example.com', 'password123');

    // Get current user info
    const user = await getCurrentUser();
    console.log('Logged in as:', user.name);

    // Logout when done
    await logout();
}
```

## Key Points

| Method | Purpose |
|--------|---------|
| `account.create()` | Creates a new user account |
| `account.createEmailPasswordSession()` | Creates a session (login) |
| `account.get()` | Gets the current authenticated user |
| `account.deleteSession()` | Logs out the user |

## Important Notes

1. **`ID.unique()`** generates a unique user ID automatically
2. **Sessions are stored in cookies** by the SDK for web apps
3. **Password requirements** depend on your Appwrite project settings (minimum length, complexity, etc.)
4. **Error handling** is essential - catch `AppwriteException` for specific error codes (401, 403, 404, etc.)
5. **Project ID** must be replaced with your actual Appwrite project ID from the console

## Error Handling Example

```typescript
import { AppwriteException } from 'appwrite';

try {
    await account.createEmailPasswordSession({
        email: 'user@example.com',
        password: 'wrongpassword'
    });
} catch (error) {
    if (error instanceof AppwriteException) {
        console.log('Error code:', error.code);      // HTTP status code
        console.log('Error type:', error.type);      // e.g., 'user_invalid_credentials'
        console.log('Message:', error.message);      // Human-readable message
    }
}
```

This implementation covers the complete authentication flow for email/password-based signup and login in a web application using Appwrite.

Here's a complete example using the Appwrite Web SDK to create a database, a "tasks" collection with the specified attributes, and insert a document:

```typescript
import { Client, TablesDB, ID, Permission, Role } from 'appwrite';

// Initialize the client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[YOUR_PROJECT_ID]');

const tablesDB = new TablesDB(client);

async function setupTasksDatabase() {
    try {
        // 1. Create a database
        const database = await tablesDB.create({
            databaseId: ID.unique(),
            name: 'Task Manager'
        });
        console.log('Database created:', database.$id);

        // 2. Create a "tasks" table with attributes
        const tasksTable = await tablesDB.createTable({
            databaseId: database.$id,
            tableId: ID.unique(),
            name: 'tasks',
            columns: [
                {
                    key: 'title',
                    type: 'varchar',
                    size: 255,
                    required: true
                },
                {
                    key: 'completed',
                    type: 'boolean',
                    required: true,
                    default: false
                },
                {
                    key: 'dueDate',
                    type: 'datetime',
                    required: false
                }
            ],
            permissions: [
                Permission.create(Role.any()),
                Permission.read(Role.any()),
                Permission.update(Role.any()),
                Permission.delete(Role.any())
            ]
        });
        console.log('Tasks table created:', tasksTable.$id);

        // 3. Insert a document (row)
        const task = await tablesDB.createRow({
            databaseId: database.$id,
            tableId: tasksTable.$id,
            rowId: ID.unique(),
            data: {
                title: 'Complete Appwrite integration',
                completed: false,
                dueDate: new Date('2025-12-31T23:59:59Z').toISOString()
            },
            permissions: [
                Permission.read(Role.any()),
                Permission.update(Role.any()),
                Permission.delete(Role.any())
            ]
        });
        console.log('Task created:', task);

        return { databaseId: database.$id, tableId: tasksTable.$id, task };
    } catch (error) {
        console.error('Error setting up tasks database:', error);
        throw error;
    }
}

// Run the setup
setupTasksDatabase();
```

## Key Points:

| Attribute | Type | Notes |
|-----------|------|-------|
| `title` | `varchar` (255) | Required, stored inline, fully indexable |
| `completed` | `boolean` | Required, defaults to `false` |
| `dueDate` | `datetime` | Optional, ISO 8601 format |

## Important Notes:

1. **Database & Table Creation**: These operations require **server-side API key authentication**. For client-side apps, create the database and tables in the Appwrite Console or via server-side code, then use the client SDK only for CRUD operations on rows.

2. **Permissions**: The example uses `Role.any()` for demonstration. In production, restrict permissions appropriately (e.g., `Role.user('[USER_ID]')` for user-specific access).

3. **Modern SDK**: This uses `TablesDB` (the current API). The older `Databases` class with `createCollection()` is deprecated.

4. **Datetime Format**: Appwrite expects ISO 8601 format strings for datetime fields (e.g., `new Date().toISOString()`).

## Client-Side Only (After Setup):

Once your database and table are created, client-side code only needs to work with rows:

```typescript
// Assuming database and table already exist
const task = await tablesDB.createRow({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    rowId: ID.unique(),
    data: {
        title: 'New task',
        completed: false,
        dueDate: new Date().toISOString()
    }
});
```

# Querying Documents in Appwrite with the Query Class

Appwrite's `Query` class provides a powerful, type-safe way to filter, sort, paginate, and select data from your database tables. Here's a comprehensive guide with practical examples.

## Basic Setup

```typescript
import { Client, TablesDB, Query } from 'appwrite'; // or 'node-appwrite' for server-side

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);
```

---

## 1. Filtering Documents

### Equality & Comparison

```typescript
// Exact match
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.equal('status', 'active')
    ]
});

// Multiple values (IN query)
const multiResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.equal('category', ['tech', 'science', 'business'])
    ]
});

// Not equal
const notActive = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.notEqual('status', 'deleted')
    ]
});

// Numeric comparisons
const highPriority = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.greaterThan('priority', 5),
        Query.lessThanEqual('priority', 10)
    ]
});

// Range query
const rangeResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.between('age', 18, 65)
    ]
});
```

### Null Checks

```typescript
// Find documents where field is null
const nullResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.isNull('completedAt')
    ]
});

// Find documents where field is not null
const completed = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.isNotNull('completedAt')
    ]
});
```

### String Operations

```typescript
// Starts with
const usersWithA = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.startsWith('name', 'A')
    ]
});

// Ends with
const gmailUsers = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.endsWith('email', '@gmail.com')
    ]
});

// Contains
const searchResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.contains('tags', 'urgent')
    ]
});

// Full-text search (requires full-text index on the field)
const textSearch = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.search('content', 'appwrite tutorial')
    ]
});
```

### Logical Operators

```typescript
// OR condition
const orResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.or([
            Query.equal('status', 'pending'),
            Query.equal('status', 'review')
        ])
    ]
});

// AND condition (queries are AND by default, but explicit AND is available)
const andResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.and([
            Query.greaterThan('age', 18),
            Query.lessThan('age', 65),
            Query.equal('verified', true)
        ])
    ]
});

// Complex query combining multiple conditions
const complexQuery = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.equal('status', 'active'),
        Query.greaterThan('score', 80),
        Query.or([
            Query.equal('role', 'admin'),
            Query.equal('role', 'moderator')
        ])
    ]
});
```

---

## 2. Sorting Documents

```typescript
// Sort ascending
const sortedAsc = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderAsc('createdAt')
    ]
});

// Sort descending
const sortedDesc = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderDesc('updatedAt')
    ]
});

// Multiple sort criteria (order matters - first criterion is primary)
const multiSort = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderDesc('priority'),  // Primary sort
        Query.orderAsc('name')        // Secondary sort
    ]
});
```

---

## 3. Limiting Results

```typescript
// Default limit is 25, max is 100
const limited = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(10)
    ]
});

// Combine with other queries
const topActive = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.equal('status', 'active'),
        Query.orderDesc('score'),
        Query.limit(5)
    ]
});
```

---

## 4. Pagination

### Offset-Based Pagination

```typescript
// Page 1 (items 0-24)
const page1 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(25),
        Query.offset(0)
    ]
});

// Page 2 (items 25-49)
const page2 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(25),
        Query.offset(25)
    ]
});

// Page 3 (items 50-74)
const page3 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(25),
        Query.offset(50)
    ]
});
```

### Cursor-Based Pagination (Recommended for Large Datasets)

```typescript
// Get first page
const firstPage = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderAsc('$createdAt'),
        Query.limit(25)
    ]
});

// Get next page using cursor
const nextPage = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderAsc('$createdAt'),
        Query.limit(25),
        Query.cursorAfter(firstPage.documents[firstPage.documents.length - 1].$id)
    ]
});

// Get previous page
const prevPage = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderAsc('$createdAt'),
        Query.limit(25),
        Query.cursorBefore(firstPage.documents[0].$id)
    ]
});
```

> **Tip:** Cursor-based pagination is more efficient for large datasets as it doesn't need to scan through skipped records.

---

## 5. Field Selection

```typescript
// Return only specific fields (reduces payload size)
const selected = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.select(['$id', 'name', 'email', 'createdAt'])
    ]
});
```

> **Note:** System fields like `$id`, `$createdAt`, `$updatedAt`, and `$permissions` are always available. Use `Query.select()` to minimize data transfer.

---

## 6. Complete Real-World Example

```typescript
// Fetch active users, sorted by creation date, paginated
async function getActiveUsers(page: number = 1, limit: number = 25) {
    const offset = (page - 1) * limit;

    const results = await tablesDB.listRows({
        databaseId: '[DATABASE_ID]',
        tableId: '[TABLE_ID]',
        queries: [
            Query.equal('status', 'active'),
            Query.isNotNull('email'),
            Query.orderDesc('createdAt'),
            Query.limit(limit),
            Query.offset(offset)
        ]
    });

    return {
        users: results.documents,
        total: results.total,
        page,
        totalPages: Math.ceil(results.total / limit)
    };
}

// Usage
const userData = await getActiveUsers(1, 20);
console.log(`Page ${userData.page} of ${userData.totalPages}`);
console.log(`Total users: ${userData.total}`);
```

---

## Query Methods Reference

| Method | Description | Example |
|--------|-------------|---------|
| `Query.equal()` | Field equals value(s) | `Query.equal('status', 'active')` |
| `Query.notEqual()` | Field not equal to value | `Query.notEqual('status', 'deleted')` |
| `Query.lessThan()` | Field < value | `Query.lessThan('age', 18)` |
| `Query.lessThanEqual()` | Field <= value | `Query.lessThanEqual('score', 100)` |
| `Query.greaterThan()` | Field > value | `Query.greaterThan('price', 50)` |
| `Query.greaterThanEqual()` | Field >= value | `Query.greaterThanEqual('rating', 4)` |
| `Query.between()` | Value in range | `Query.between('age', 18, 65)` |
| `Query.isNull()` | Field is null | `Query.isNull('deletedAt')` |
| `Query.isNotNull()` | Field is not null | `Query.isNotNull('email')` |
| `Query.startsWith()` | String starts with | `Query.startsWith('name', 'John')` |
| `Query.endsWith()` | String ends with | `Query.endsWith('email', '@gmail.com')` |
| `Query.contains()` | String/array contains | `Query.contains('tags', 'urgent')` |
| `Query.search()` | Full-text search | `Query.search('content', 'keywords')` |
| `Query.orderAsc()` | Sort ascending | `Query.orderAsc('createdAt')` |
| `Query.orderDesc()` | Sort descending | `Query.orderDesc('updatedAt')` |
| `Query.limit()` | Max results | `Query.limit(25)` |
| `Query.offset()` | Skip N results | `Query.offset(50)` |
| `Query.cursorAfter()` | Paginate after ID | `Query.cursorAfter('[ID]')` |
| `Query.cursorBefore()` | Paginate before ID | `Query.cursorBefore('[ID]')` |
| `Query.select()` | Select fields | `Query.select(['name', 'email'])` |
| `Query.or()` | OR condition | `Query.or([q1, q2])` |
| `Query.and()` | AND condition | `Query.and([q1, q2])` |

---

## Best Practices

1. **Use cursor-based pagination** for large datasets (more efficient than offset)
2. **Combine filters early** to reduce data transfer
3. **Use `Query.select()`** to fetch only needed fields
4. **Index frequently queried fields** in your table settings for better performance
5. **Keep queries under 100 results** per request (Appwrite's max limit)
6. **Use full-text search** only on fields with full-text indexes enabled

Here's an Appwrite Function in Node.js that receives a JSON body with a "name" field and returns a personalized greeting:

```javascript
module.exports = async function(context) {
    const { req, res, log, error } = context;

    try {
        // Parse the request body
        const body = req.body || {};
        const name = body.name;

        // Validate the name field
        if (!name || typeof name !== 'string') {
            return res.json({
                success: false,
                error: 'Missing or invalid "name" field in request body'
            }, 400);
        }

        // Create personalized greeting
        const greeting = `Hello, ${name}! Welcome to Appwrite Functions.`;

        log(`Greeting generated for: ${name}`);

        // Return success response
        return res.json({
            success: true,
            greeting: greeting,
            timestamp: new Date().toISOString()
        });

    } catch (err) {
        error(`Function error: ${err.message}`);

        return res.json({
            success: false,
            error: 'Internal server error'
        }, 500);
    }
};
```

## Key Points:

### Function Signature
- **Export**: `module.exports = async function(context)`
- **Context object** contains:
  - `req` - Request object (headers, query, body, etc.)
  - `res` - Response object for sending responses
  - `log` - Logging function
  - `error` - Error logging function

### Response Format
- Use `res.json(data, statusCode)` to return JSON responses
- Include appropriate HTTP status codes (200, 400, 500, etc.)
- Return structured data with `success`, `greeting`, and `error` fields

### Testing the Function

Using the Appwrite CLI:
```bash
appwrite functions create-execution \
    --function-id <YOUR_FUNCTION_ID> \
    --body '{"name": "John"}'
```

Expected response:
```json
{
    "success": true,
    "greeting": "Hello, John! Welcome to Appwrite Functions.",
    "timestamp": "2024-01-15T10:30:00.000Z"
}
```

### Function Configuration (appwrite.config.json)
```json
{
    "functions": [
        {
            "$id": "greeting-function",
            "name": "Greeting Function",
            "enabled": true,
            "live": true,
            "logging": true,
            "runtime": "node-18.0",
            "entrypoint": "index.js",
            "commands": "npm install",
            "version": "v3",
            "path": "functions/greeting"
        }
    ]
}
```

This function follows Appwrite's best practices for error handling, logging, and response formatting.

Here are at least three `APPWRITE_FUNCTION_*` environment variables available inside an Appwrite Function at runtime:

| Environment Variable | Description |
|---------------------|-------------|
| **`APPWRITE_FUNCTION_EVENT`** | Contains the event string that triggered the function execution (e.g., `functions.[FUNCTION_ID].executions`, `databases.[DATABASE_ID].tables.[TABLE_ID].rows.[ROW_ID].create`, `users.[USER_ID].update`). Useful for determining why the function was invoked. |
| **`APPWRITE_FUNCTION_EVENT_DATA`** | Contains the JSON payload/data associated with the triggering event. For example, if triggered by a document creation, this contains the created document's data. If triggered manually, this contains the body passed to the execution. |
| **`APPWRITE_FUNCTION_ID`** | The unique ID of the function being executed. Useful for logging, debugging, or making API calls related to the function itself. |
| **`APPWRITE_FUNCTION_PROJECT_ID`** | The project ID associated with the function. Used when initializing Appwrite SDK clients to ensure you're working with the correct project. |
| **`APPWRITE_FUNCTION_API_ENDPOINT`** | The base URL for the Appwrite API (e.g., `https://cloud.appwrite.io/v1`). Use this when initializing the Appwrite SDK client inside your function. |
| **`APPWRITE_FUNCTION_API_KEY`** | A server-side API key with permissions to interact with Appwrite services. Only available for certain trigger types (not available for HTTP triggers). Use this for admin-level operations. |
| **`APPWRITE_FUNCTION_RUNTIME`** | The runtime environment identifier (e.g., `node-18.0`, `python-3.10`, `php-8.1`). Useful for runtime-specific logic or logging. |
| **`APPWRITE_FUNCTION_TIMEOUT`** | The maximum execution time for the function in seconds. Helps you manage long-running operations. |
| **`APPWRITE_FUNCTION_ENV`** | The deployment environment (e.g., `dev`, `preview`, `production`). Useful for environment-specific configuration. |

### Example Usage in a Node.js Function

```typescript
export default async ({ req, res, log, error }) => {
    const projectId = process.env.APPWRITE_FUNCTION_PROJECT_ID;
    const endpoint = process.env.APPWRITE_FUNCTION_API_ENDPOINT;
    const apiKey = process.env.APPWRITE_FUNCTION_API_KEY;
    const event = process.env.APPWRITE_FUNCTION_EVENT;
    const eventData = JSON.parse(process.env.APPWRITE_FUNCTION_EVENT_DATA || '{}');

    log(`Function ${process.env.APPWRITE_FUNCTION_ID} triggered by: ${event}`);
    log(`Event data: ${JSON.stringify(eventData)}`);

    // Use SDK with these values
    // const client = new Client().setEndpoint(endpoint).setProject(projectId).setKey(apiKey);

    return res.json({ success: true });
};
```

> **Note:** `APPWRITE_FUNCTION_API_KEY` is only available for functions triggered by Appwrite events (not HTTP triggers). For HTTP-triggered functions, you'll need to handle authentication differently.

Here's a complete example using the Appwrite Web SDK to create a bucket, upload a file, and get a preview URL with proper permission configuration:

## Setup

```typescript
import { Client, Storage, Permission, Role, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);
```

## 1. Create a Bucket (Server-Side Only)

Bucket creation requires admin privileges, so use the server SDK with an API key:

```typescript
// server.ts (Node.js/Deno)
import { Client, Storage, Permission, Role } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject(process.env.APPWRITE_PROJECT_ID)
    .setKey(process.env.APPWRITE_API_KEY);

const storage = new Storage(client);

// Create bucket with permissions
const bucket = await storage.createBucket({
    bucketId: ID.unique(),
    name: 'User Uploads',
    fileSecurity: true, // Enable file-level permissions
    permissions: [
        Permission.create(Role.user('[USER_ID]')),      // Specific user can create files
        Permission.read(Role.team('[TEAM_ID]')),        // Team members can read
        Permission.read(Role.any()),                    // Public read access (optional)
    ],
    enabled: true,
    maximumFileSize: 5 * 1024 * 1024, // 5MB
    allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp'],
});

console.log('Bucket created:', bucket.$id);
```

## 2. Upload a File (Client-Side)

```typescript
// client.ts (Browser/React/Vue/etc.)
import { Client, Storage, Permission, Role, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);

// Get file from input element
const fileInput = document.getElementById('file-input') as HTMLInputElement;
const file = fileInput.files?.[0];

if (!file) {
    throw new Error('No file selected');
}

// Upload file with permissions
const uploadedFile = await storage.createFile({
    bucketId: '[BUCKET_ID]',
    fileId: ID.unique(),
    file: file,
    permissions: [
        Permission.read(Role.any()),                    // Public read (for preview)
        Permission.update(Role.user('[USER_ID]')),      // Owner can update
        Permission.delete(Role.user('[USER_ID]')),      // Owner can delete
    ],
});

console.log('File uploaded:', uploadedFile.$id);
```

## 3. Get Preview URL for Image

```typescript
// Generate preview URL (client-side or server-side)
const previewUrl = storage.getFilePreview({
    bucketId: '[BUCKET_ID]',
    fileId: uploadedFile.$id,
    width: 400,      // Optional: resize width
    height: 400,     // Optional: resize height
    gravity: 'center', // Optional: crop gravity
    quality: 90,     // Optional: JPEG quality (1-100)
});

console.log('Preview URL:', previewUrl);

// Use in an image element
const img = document.createElement('img');
img.src = previewUrl;
img.alt = uploadedFile.name;
document.body.appendChild(img);
```

## 4. Complete Example with Error Handling

```typescript
import { Client, Storage, Permission, Role, ID, AppwriteException } from 'appwrite';

class FileUploader {
    private storage: Storage;
    private bucketId: string;
    private userId: string;

    constructor(projectId: string, bucketId: string, userId: string) {
        const client = new Client()
            .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
            .setProject(projectId);

        this.storage = new Storage(client);
        this.bucketId = bucketId;
        this.userId = userId;
    }

    async uploadImage(file: File): Promise<string> {
        try {
            // Upload with permissions
            const uploadedFile = await this.storage.createFile({
                bucketId: this.bucketId,
                fileId: ID.unique(),
                file: file,
                permissions: [
                    Permission.read(Role.any()),
                    Permission.update(Role.user(this.userId)),
                    Permission.delete(Role.user(this.userId)),
                ],
            });

            // Generate preview URL
            const previewUrl = this.storage.getFilePreview({
                bucketId: this.bucketId,
                fileId: uploadedFile.$id,
                width: 300,
                height: 300,
                quality: 85,
            });

            return previewUrl;
        } catch (error) {
            if (error instanceof AppwriteException) {
                console.error(`Appwrite Error ${error.code}:`, error.message);

                if (error.code === 403) {
                    throw new Error('Permission denied. Check bucket/file permissions.');
                } else if (error.code === 413) {
                    throw new Error('File too large.');
                } else if (error.code === 400) {
                    throw new Error('Invalid file type.');
                }
            }
            throw error;
        }
    }

    async getPreviewUrl(fileId: string, width = 300, height = 300): Promise<string> {
        return this.storage.getFilePreview({
            bucketId: this.bucketId,
            fileId: fileId,
            width,
            height,
        });
    }
}

// Usage
const uploader = new FileUploader('[PROJECT_ID]', '[BUCKET_ID]', '[USER_ID]');

// Handle file input
document.getElementById('upload-btn')?.addEventListener('click', async () => {
    const fileInput = document.getElementById('file-input') as HTMLInputElement;
    const file = fileInput.files?.[0];

    if (file) {
        try {
            const previewUrl = await uploader.uploadImage(file);

            // Display preview
            const img = document.createElement('img');
            img.src = previewUrl;
            img.style.maxWidth = '300px';
            document.getElementById('preview-container')?.appendChild(img);
        } catch (error) {
            console.error('Upload failed:', error);
            alert('Upload failed: ' + (error as Error).message);
        }
    }
});
```

## Key Permission Patterns

| Permission | Use Case |
|------------|----------|
| `Permission.read(Role.any())` | Public images (profiles, products) |
| `Permission.read(Role.user('[ID]'))` | Private user files |
| `Permission.read(Role.team('[ID]'))` | Team-shared resources |
| `Permission.write(Role.user('[ID]'))` | Owner can update/delete |

## Important Notes

1. **Bucket creation** requires server-side code with an API key (not client-side)
2. **File permissions** are required—without them, no one can access the file (including the uploader)
3. **Preview URLs** are public by default if the file has `read` permission for `Role.any()`
4. **File security** must be enabled on the bucket to use file-level permissions
5. **Supported image formats** for previews: JPG, PNG, GIF, WebP, SVG

Based on my knowledge of Appwrite Messaging, here's how message targeting works:

## Message Targeting in Appwrite Messaging

Appwrite Messaging supports three primary targeting methods for delivering push notifications, emails, and SMS:

### 1. **User Targeting**
Send messages to specific authenticated users by their User ID:

```typescript
import { Messaging, Role } from 'node-appwrite';

const messaging = new Messaging(client);

await messaging.createMessage({
    messageId: ID.unique(),
    topic: 'users',
    content: 'Hello specific user!',
    subjects: ['Welcome!'],
    content: 'Your message content',
    targets: ['user-id-123'], // Specific user IDs
    providerId: '[PROVIDER_ID]',
});
```

### 2. **Topic Targeting**
Send messages to all subscribers of a topic. Users must subscribe to topics first:

```typescript
// Create a topic
await messaging.createTopic({
    topicId: 'news-updates',
    name: 'News Updates'
});

// Subscribe a user to a topic
await messaging.createSubscription({
    topicId: 'news-updates',
    userId: '[USER_ID]',
    providerId: '[PROVIDER_ID]',
    providerResourceId: 'device-token-or-email'
});

// Send message to all topic subscribers
await messaging.createMessage({
    messageId: ID.unique(),
    topicId: 'news-updates',
    content: 'Breaking news!',
    subjects: ['News Alert'],
    providerId: '[PROVIDER_ID]',
});
```

### 3. **Individual Targets**
Send messages directly to specific device tokens, email addresses, or phone numbers without requiring user accounts:

```typescript
await messaging.createMessage({
    messageId: ID.unique(),
    topic: 'external',
    content: 'Message to external target',
    subjects: ['Notification'],
    targets: [
        'device-token-abc123',  // Push notification token
        'user@example.com',      // Email address
        '+1234567890'           // Phone number (SMS)
    ],
    providerId: '[PROVIDER_ID]',
});
```

## Key Concepts

| Target Type | Use Case | Requirements |
|-------------|----------|--------------|
| **User IDs** | Authenticated users | User must exist in Appwrite Auth |
| **Topics** | Broadcast to groups | Users must subscribe to the topic |
| **External Targets** | One-off or anonymous recipients | Valid token/email/phone number |

## Provider Configuration

Messages require a configured **Provider** (push, email, or SMS) before sending:

```typescript
// Create an email provider
await messaging.createProvider({
    providerId: 'email-provider',
    type: 'email',
    name: 'SendGrid',
    enabled: true,
    credentials: {
        apiKey: 'your-api-key',
        from: 'noreply@example.com',
        fromName: 'My App'
    }
});
```

## Best Practices

1. **Use Topics for broadcasts** - More efficient than sending to individual users
2. **Combine targeting methods** - You can send to users AND topics in one message
3. **Manage subscriptions** - Allow users to subscribe/unsubscribe from topics
4. **Validate targets** - Ensure device tokens, emails, and phone numbers are valid

> **Note:** The specific Messaging SDK methods may vary slightly depending on your Appwrite version. Check your Appwrite console for the most current API structure, as Messaging is an evolving service.

Here's a complete example using the Appwrite Web SDK to subscribe to both realtime document changes and file uploads simultaneously, with different handling for each event type:

```typescript
import { Client, Realtime, Channel, ID } from 'appwrite';

// Initialize the Appwrite client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[YOUR_PROJECT_ID]');

// Initialize Realtime
const realtime = new Realtime(client);

// Subscribe to both document changes and file uploads
const subscription = await realtime.subscribe(
    [
        // Subscribe to all row changes in a specific table
        Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
        // Subscribe to all file uploads in a specific bucket
        Channel.bucket('[BUCKET_ID]').file(),
    ],
    (response) => {
        // Check which type of event occurred
        const event = response.events[0];

        // Handle document/row events
        if (event.includes('tablesdb') && event.includes('rows')) {
            handleDocumentEvent(event, response.payload);
        }
        // Handle file events
        else if (event.includes('buckets') && event.includes('files')) {
            handleFileEvent(event, response.payload);
        }
    }
);

// Handle document events differently
function handleDocumentEvent(event: string, payload: any) {
    if (event.includes('.create')) {
        console.log('📄 New document created:', payload.$id);
        console.log('Document data:', payload);
        // Add new document to UI list, show notification, etc.
    } 
    else if (event.includes('.update')) {
        console.log('✏️ Document updated:', payload.$id);
        console.log('Updated fields:', payload);
        // Update specific document in UI, sync changes, etc.
    } 
    else if (event.includes('.delete')) {
        console.log('🗑️ Document deleted:', payload.$id);
        // Remove document from UI, show confirmation, etc.
    }
}

// Handle file events differently
function handleFileEvent(event: string, payload: any) {
    if (event.includes('.create')) {
        console.log('📁 New file uploaded:', payload.$id);
        console.log('File name:', payload.name);
        console.log('File size:', payload.sizeOriginal);
        console.log('MIME type:', payload.mimeType);

        // Generate preview URL for images
        if (payload.mimeType?.startsWith('image/')) {
            const previewUrl = client.config.endpoint + 
                '/storage/buckets/' + payload.$bucketId + 
                '/files/' + payload.$id + '/preview?width=300&height=300';
            console.log('Preview URL:', previewUrl);
            // Display image preview in UI
        }

        // Add file to gallery, show upload progress complete, etc.
    } 
    else if (event.includes('.update')) {
        console.log('🔄 File metadata updated:', payload.$id);
        // Update file info in UI
    } 
    else if (event.includes('.delete')) {
        console.log('🗑️ File deleted:', payload.$id);
        // Remove file from UI gallery
    }
}

// Optional: Subscribe to a specific document only
// const specificDocSubscription = await realtime.subscribe(
//     Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row('[SPECIFIC_ROW_ID]'),
//     (response) => {
//         console.log('Specific document changed:', response.payload);
//     }
// );

// Optional: Subscribe to a specific file only
// const specificFileSubscription = await realtime.subscribe(
//     Channel.bucket('[BUCKET_ID]').file('[SPECIFIC_FILE_ID]'),
//     (response) => {
//         console.log('Specific file changed:', response.payload);
//     }
// );

// Cleanup: Close subscription when component unmounts or no longer needed
// await subscription.close();
```

## Key Points:

1. **Multiple Channels**: Pass an array of channels to `subscribe()` to listen to multiple event types simultaneously.

2. **Event Detection**: Use `response.events[0]` to check the event type. Event strings follow patterns like:
   - Documents: `tablesdb.*.tables.*.rows.*.create`, `.update`, `.delete`
   - Files: `buckets.*.files.*.create`, `.update`, `.delete`

3. **Response Object**: Contains:
   - `events`: Array of event strings that triggered the callback
   - `payload`: The affected resource (document or file metadata)
   - `channels`: Which channels matched
   - `timestamp`: ISO 8601 timestamp

4. **Different Handling**: The example shows distinct logic for documents vs. files, including:
   - Document: Track CRUD operations, sync UI state
   - Files: Generate preview URLs for images, handle file metadata

5. **Cleanup**: Always call `subscription.close()` when you no longer need realtime updates (e.g., component unmount in React).

## React Example (with cleanup):

```typescript
import { useEffect } from 'react';
import { Client, Realtime, Channel } from 'appwrite';

function RealtimeComponent() {
    useEffect(() => {
        const client = new Client()
            .setEndpoint('https://cloud.appwrite.io/v1')
            .setProject('[PROJECT_ID]');

        const realtime = new Realtime(client);

        const subscription = realtime.subscribe(
            [
                Channel.tablesdb('[DB_ID]').table('[TABLE_ID]').row(),
                Channel.bucket('[BUCKET_ID]').file(),
            ],
            (response) => {
                if (response.events[0].includes('rows')) {
                    // Handle document
                } else {
                    // Handle file
                }
            }
        );

        // Cleanup on unmount
        return () => {
            subscription.close();
        };
    }, []);

    return <div>Realtime active</div>;
}
```

Based on the Appwrite TypeScript SDK documentation, here's how to subscribe to both a database collection's documents and a storage bucket's files in a single call:

## Using Channel Helpers (Recommended)

```typescript
import { Realtime, Channel } from 'appwrite';

const realtime = new Realtime(client);

await realtime.subscribe([
    Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
    Channel.bucket('[BUCKET_ID]').file(),
], (response) => {
    console.log(response.events);   // e.g. ['tablesdb.*.tables.*.rows.*.create'] or ['buckets.*.files.*.create']
    console.log(response.payload);  // the affected document or file
});
```

## Exact Channel Strings

The raw channel strings are:

| Resource | Channel String |
|----------|----------------|
| All documents in a table | `tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows` |
| All files in a bucket | `buckets.[BUCKET_ID].files` |

## Using Raw Channel Strings Directly

```typescript
await realtime.subscribe([
    'tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows',
    'buckets.[BUCKET_ID].files',
], (response) => {
    // Handle both document and file events
});
```

## Key Points

- Pass an **array of channels** to `subscribe()` to listen to multiple resources
- The `response.events` array tells you which event type triggered the callback (e.g., `create`, `update`, `delete`)
- The `response.payload` contains the affected document or file metadata
- Replace `[DATABASE_ID]`, `[TABLE_ID]`, and `[BUCKET_ID]` with your actual IDs

Here's a complete implementation for email/password authentication using the Appwrite Web SDK:

## Setup

```bash
npm install appwrite
```

## Implementation

```typescript
import { Client, Account, ID, AppwriteException } from 'appwrite';

// 1. Set up the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')  // Your Appwrite endpoint
    .setProject('[PROJECT_ID]');                           // Your project ID

// 2. Create the Account instance
const account = new Account(client);

// ==================== SIGN UP ====================

async function signUp(email: string, password: string, name: string) {
    try {
        const user = await account.create({
            userId: ID.unique(),    // Generate a unique ID for the user
            email: email,
            password: password,
            name: name
        });

        console.log('User created:', user);

        // Automatically log in the user after signup
        await createSession(email, password);

        return user;
    } catch (error) {
        if (error instanceof AppwriteException) {
            console.error('Signup failed:', error.message);
            throw error;
        }
    }
}

// ==================== LOGIN ====================

async function createSession(email: string, password: string) {
    try {
        const session = await account.createEmailPasswordSession({
            email: email,
            password: password
        });

        console.log('Session created:', session);
        return session;
    } catch (error) {
        if (error instanceof AppwriteException) {
            console.error('Login failed:', error.message);
            throw error;
        }
    }
}

// ==================== GET CURRENT USER ====================

async function getCurrentUser() {
    try {
        const user = await account.get();
        console.log('Current user:', user);
        return user;
    } catch (error) {
        if (error instanceof AppwriteException) {
            console.error('Not logged in:', error.message);
            return null;
        }
    }
}

// ==================== LOGOUT ====================

async function logout() {
    try {
        // Delete the current session
        await account.deleteSession({ sessionId: 'current' });
        console.log('Logged out successfully');
    } catch (error) {
        if (error instanceof AppwriteException) {
            console.error('Logout failed:', error.message);
            throw error;
        }
    }
}

// ==================== USAGE EXAMPLE ====================

async function authExample() {
    // Sign up a new user
    await signUp('user@example.com', 'password123', 'John Doe');

    // Or log in an existing user
    // await createSession('user@example.com', 'password123');

    // Get the logged-in user
    const user = await getCurrentUser();

    // Log out
    await logout();
}

authExample();
```

## Key Points

- **Client setup**: Configure your endpoint and project ID once. The SDK handles session cookies automatically.
- **ID.unique()**: Generates a secure unique ID for the new user.
- **Session persistence**: After `createEmailPasswordSession()`, the SDK stores the session cookie and sends it with subsequent requests.
- **Error handling**: Use `AppwriteException` to catch and handle authentication errors like invalid credentials or duplicate emails.

Replace `https://<REGION>.cloud.appwrite.io/v1` and `[PROJECT_ID]` with your actual Appwrite endpoint and project ID from your Appwrite console.

Based on the Appwrite TypeScript SDK documentation, I need to clarify an important point: **creating databases and collections requires server-side permissions** (API key). The Web SDK (client-side) can only create documents within existing collections.

Here's the complete solution with both **server-side setup** (database + collection creation) and **client-side** document insertion:

## Server-Side: Create Database, Collection & Attributes

> **Note:** Database and collection creation requires server-side permissions with an API key.

```typescript
import { Client, TablesDB, ID } from 'node-appwrite';

// Server-side client with API key
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey(process.env.APPWRITE_API_KEY); // Your API key here

const tablesDB = new TablesDB(client);

async function setupTasksCollection() {
    // 1. Create database
    const database = await tablesDB.create({
        databaseId: ID.unique(),
        name: 'Task Database'
    });

    // 2. Create collection (table) with attributes (columns)
    const collection = await tablesDB.createTable({
        databaseId: database.$id,
        tableId: 'tasks', // You can use ID.unique() or a custom ID
        name: 'Tasks',
        columns: [
            { key: 'title',      type: 'varchar', size: 255, required: true },
            { key: 'completed',  type: 'boolean',            required: true, default: false },
            { key: 'dueDate',    type: 'datetime',           required: false }
        ]
    });

    console.log('Database ID:', database.$id);
    console.log('Collection ID:', collection.$id);

    return { databaseId: database.$id, tableId: collection.$id };
}
```

## Client-Side (Web): Insert a Document

```typescript
import { Client, TablesDB, ID, Permission, Role } from 'appwrite';

// Client-side client (no API key)
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

async function createTask(databaseId: string, tableId: string, userId: string) {
    // 3. Insert a document (row)
    const task = await tablesDB.createRow({
        databaseId: databaseId,
        tableId: tableId,
        rowId: ID.unique(),
        data: {
            title: 'Complete Appwrite integration',
            completed: false,
            dueDate: new Date('2025-01-15T10:00:00.000Z').toISOString()
        },
        permissions: [
            Permission.read(Role.user(userId)),   // Only the user can read
            Permission.update(Role.user(userId)), // Only the user can update
            Permission.delete(Role.user(userId))  // Only the user can delete
        ]
    });

    console.log('Task created:', task);
    return task;
}
```

## Complete Working Example

```typescript
import { Client, TablesDB, ID, Permission, Role } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // or your region endpoint
    .setProject('your-project-id');

const tablesDB = new TablesDB(client);

// Assuming you have already created the database and collection in Appwrite Console
// or via server-side code above

const DATABASE_ID = 'your-database-id';
const COLLECTION_ID = 'tasks';

async function addTask() {
    try {
        const task = await tablesDB.createRow({
            databaseId: DATABASE_ID,
            tableId: COLLECTION_ID,
            rowId: ID.unique(),
            data: {
                title: 'Learn Appwrite',
                completed: false,
                dueDate: new Date().toISOString()
            }
        });
        console.log('Task added:', task);
    } catch (error) {
        console.error('Error:', error);
    }
}

addTask();
```

## Important Notes

1. **Database/Collection Creation** is a **server-side only** operation requiring an API key. Use `node-appwrite` for this.

2. **Document Creation** can be done from the client-side (Web SDK) if the user has appropriate permissions.

3. **Column Types**: The new API uses explicit types:
   - `varchar` for strings (with size limit)
   - `boolean` for true/false
   - `datetime` for dates

4. **Permissions**: Documents are private by default. Use `Permission` and `Role` helpers to set access control.

5. **Appwrite Console**: As an alternative, you can create the database and collection manually in the Appwrite Console, then just use the client-side code to insert documents.

The Appwrite `Query` class provides a fluent API for filtering, sorting, and paginating data. Here's a comprehensive guide with examples using the modern `TablesDB` API (which replaces the deprecated `Databases` class):

## Importing Query

```typescript
import { Query } from 'appwrite';        // Client-side
// or
import { Query } from 'node-appwrite';   // Server-side
```

## Basic Query Structure

Pass an array of queries to `listRows()`:

```typescript
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.equal('status', 'active'),
        Query.limit(25)
    ]
});
```

## 1. Filtering

### Equality & Inequality
```typescript
// Exact match
Query.equal('status', 'active')

// Match multiple values (IN operator)
Query.equal('category', ['tech', 'science'])

// Not equal
Query.notEqual('status', 'archived')
```

### Numeric Comparisons
```typescript
Query.lessThan('price', 100)           // price < 100
Query.lessThanEqual('age', 65)         // age <= 65
Query.greaterThan('score', 0)          // score > 0
Query.greaterThanEqual('rating', 4)    // rating >= 4

// Range check (inclusive)
Query.between('price', 10, 100)        // 10 <= price <= 100
```

### String Operations
```typescript
Query.startsWith('name', 'John')       // name LIKE 'John%'
Query.endsWith('email', '@gmail.com')  // email LIKE '%@gmail.com'
Query.contains('title', 'tutorial')    // title LIKE '%tutorial%'
```

### Null Checks
```typescript
Query.isNull('deletedAt')              // deletedAt IS NULL
Query.isNotNull('publishedAt')         // publishedAt IS NOT NULL
```

### Array Contains
```typescript
// For array attributes
Query.contains('tags', 'javascript')   // tags contains 'javascript'
```

### Full-Text Search
```typescript
// Requires a full-text index on the field
Query.search('content', 'appwrite database')
```

### Logical Operators
```typescript
// OR condition
Query.or([
    Query.equal('status', 'draft'),
    Query.equal('status', 'review')
])

// Explicit AND (default behavior - all queries are ANDed together)
Query.and([
    Query.greaterThan('age', 18),
    Query.lessThan('age', 65)
])
```

## 2. Sorting

```typescript
// Ascending order
Query.orderAsc('createdAt')

// Descending order
Query.orderDesc('score')

// Multiple sorts (apply in order)
queries: [
    Query.orderDesc('priority'),
    Query.orderAsc('createdAt')
]
```

## 3. Limiting Results

```typescript
Query.limit(10)    // Return max 10 rows (default: 25, max: 100)
```

## 4. Pagination

### Offset Pagination (for small datasets)
```typescript
// Page 1
await tablesDB.listRows({
    tableId: '[TABLE_ID]',
    queries: [Query.limit(25), Query.offset(0)]
});

// Page 2
await tablesDB.listRows({
    tableId: '[TABLE_ID]',
    queries: [Query.limit(25), Query.offset(25)]
});
```

### Cursor Pagination (preferred for large datasets)
More efficient for large tables as it doesn't scan skipped rows:

```typescript
// First page
const firstPage = await tablesDB.listRows({
    tableId: '[TABLE_ID]',
    queries: [Query.limit(25), Query.orderAsc('createdAt')]
});

// Get last document ID for next page
const lastId = firstPage.documents[firstPage.documents.length - 1].$id;

// Next page (rows after the cursor)
const nextPage = await tablesDB.listRows({
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(25),
        Query.orderAsc('createdAt'),
        Query.cursorAfter(lastId)
    ]
});

// Previous page (rows before the cursor)
const prevPage = await tablesDB.listRows({
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(25),
        Query.orderAsc('createdAt'),
        Query.cursorBefore(firstPage.documents[0].$id)
    ]
});
```

## 5. Field Selection

Return only specific fields to reduce payload size:
```typescript
Query.select(['title', 'status', 'createdAt'])
```

## Complete Examples

### Example 1: Active Products with Pagination
```typescript
const products = await tablesDB.listRows({
    databaseId: 'shop',
    tableId: 'products',
    queries: [
        Query.equal('status', 'active'),
        Query.greaterThan('stock', 0),
        Query.orderDesc('popularity'),
        Query.limit(20),
        Query.offset(0)
    ]
});
```

### Example 2: Search with Filters
```typescript
const articles = await tablesDB.listRows({
    databaseId: 'blog',
    tableId: 'articles',
    queries: [
        Query.search('content', 'appwrite'),
        Query.equal('published', true),
        Query.isNotNull('publishedAt'),
        Query.orderDesc('publishedAt'),
        Query.limit(10)
    ]
});
```

### Example 3: Date Range Query
```typescript
const orders = await tablesDB.listRows({
    databaseId: 'sales',
    tableId: 'orders',
    queries: [
        Query.between('createdAt', '2024-01-01', '2024-12-31'),
        Query.equal('status', 'completed'),
        Query.greaterThan('total', 100),
        Query.orderDesc('total'),
        Query.limit(50)
    ]
});
```

### Example 4: Complex OR/AND Logic
```typescript
const tasks = await tablesDB.listRows({
    databaseId: 'project',
    tableId: 'tasks',
    queries: [
        Query.and([
            Query.or([
                Query.equal('assignee', userId),
                Query.contains('watchers', userId)
            ]),
            Query.notEqual('status', 'archived')
        ]),
        Query.orderAsc('dueDate'),
        Query.limit(25)
    ]
});
```

### Example 5: Cursor-Based Pagination Function
```typescript
async function fetchTasks(cursor: string | null, direction: 'next' | 'prev' = 'next') {
    const queries: string[] = [
        Query.equal('status', 'pending'),
        Query.orderAsc('priority'),
        Query.limit(25)
    ];

    if (cursor) {
        queries.push(
            direction === 'next' 
                ? Query.cursorAfter(cursor) 
                : Query.cursorBefore(cursor)
        );
    }

    return await tablesDB.listRows({
        databaseId: 'project',
        tableId: 'tasks',
        queries
    });
}
```

## Key Points

- **Default limit**: 25 rows (max 100)
- **Query combination**: Multiple queries are ANDed together by default
- **Indexes**: Ensure fields used in filters/sorts are indexed for performance
- **Cursor pagination**: Preferred over offset for large datasets as it's more performant
- **Response**: Contains `documents` array and `total` count for pagination UI

Here's a Node.js Appwrite Function that receives a JSON body with a "name" field and returns a personalized greeting:

```javascript
// src/main.js
export default async ({ req, res, log, error }) => {
  try {
    // Parse JSON body using req.bodyJson (automatically parsed by Appwrite)
    const data = req.bodyJson;

    // Validate that name field exists
    if (!data || typeof data.name !== 'string' || data.name.trim() === '') {
      return res.json({ 
        success: false, 
        error: 'Missing or invalid "name" field in request body' 
      }, 400);
    }

    const name = data.name.trim();

    // Log for debugging (appears in function logs)
    log(`Received greeting request for: ${name}`);

    // Return personalized greeting
    return res.json({
      success: true,
      message: `Hello, ${name}! Welcome to Appwrite!`
    });

  } catch (err) {
    error('Error processing request:', err.message);

    return res.json({ 
      success: false, 
      error: 'Internal server error' 
    }, 500);
  }
};
```

### Key Function Details:

| Property | Description |
|----------|-------------|
| `req.bodyJson` | Parsed JSON body (object). Returns `undefined` if body isn't valid JSON |
| `req.body` | Raw request body string |
| `req.headers` | Request headers object |
| `req.method` | HTTP method (GET, POST, etc.) |
| `req.query` | Parsed query parameters |
| `res.json(data, status)` | Send JSON response with optional status code (default 200) |
| `log(msg)` | Write to function logs |
| `error(msg)` | Write error to function logs |

### Deploying the Function

1. **Create the function:**
   ```bash
   appwrite init functions
   ```
   - Select `node-18.0` or `node-20.0` runtime
   - Entrypoint: `src/main.js`

2. **Push to Appwrite:**
   ```bash
   appwrite push functions
   ```

3. **Test the function:**
   ```bash
   appwrite functions create-execution \
       --function-id <FUNCTION_ID> \
       --body '{"name": "Alice"}'
   ```

**Expected response:**
```json
{
  "success": true,
  "message": "Hello, Alice! Welcome to Appwrite!"
}
```

