//     allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp']
// });

// ==========================================
// 3. UPLOAD A FILE (Client-side)
// ==========================================
async function uploadImage(file: File, userId: string) {
    try {
        const uploadedFile = await storage.createFile({
            bucketId: '[BUCKET_ID]',
