function getImagePreviewUrl(fileId: string, options?: {
    width?: number;
    height?: number;
    quality?: number;
    format?: 'jpg' | 'jpeg' | 'gif' | 'png' | 'webp';
}) {
    const previewUrl = storage.getFilePreview({
        bucketId: '[BUCKET_ID]',
        fileId: fileId,
        width: options?.width ?? 300,
        height: options?.height ?? 300,
        quality: options?.quality ?? 80,
        // Optional transformations:
        // gravity: 'center',     // focal point: center, top, bottom, left, right
        // border: '10,FFFFFF',   // 10px white border
        // borderRadius: 10,      // rounded corners
        // opacity: 0.9,          // transparency
        // rotation: 90,          // rotate degrees
        // background: '000000',  // background color for transparent images
        // output: 'webp'         // force format
    });

    return previewUrl; // Returns a direct URL string
}

// Usage:
// <img src={getImagePreviewUrl('file-id', { width: 400, height: 400 })} alt="Preview" />

// ==========================================
