## 5. Complete Example with All Operations

```typescript
import { Client, Account, ID, AppwriteException } from 'appwrite';

// Initialize client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const account = new Account(client);

// Sign up a new user
async function signUp(email: string, password: string, name?: string) {
    try {
        const user = await account.create({
            userId: ID.unique(),
            email,
            password,
            name
        });
        return user;
    } catch (err) {
        if (err instanceof AppwriteException) {
            console.error('Signup error:', err.message);
        }
        throw err;
    }
}

// Log in (create session)
async function login(email: string, password: string) {
    try {
        const session = await account.createEmailPasswordSession({
            email,
            password
        });
        return session;
    } catch (err) {
        if (err instanceof AppwriteException) {
            console.error('Login error:', err.message);
        }
        throw err;
    }
}

// Get current logged-in user
async function getCurrentUser() {
    try {
        const user = await account.get();
        return user;
    } catch (err) {
        return null; // Not logged in
    }
}

// Log out (delete current session)
async function logout() {
    await account.deleteSession({ sessionId: 'current' });
}

// Usage example
async function main() {
    // Sign up
    const newUser = await signUp('user@example.com', 'password123', 'John Doe');
    console.log('Created user:', newUser.$id);

    // Log in
    const session = await login('user@example.com', 'password123');
    console.log('Logged in, session expires:', session.expire);

    // Get current user
    const currentUser = await getCurrentUser();
