    "email": "test@example.com"
}
```

**Response (400):**
```json
{
    "error": "Name is required"
}
```

Here's a complete example using the Appwrite Web SDK to create a bucket, upload a file, and get a preview URL:

```typescript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// Initialize the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);

// ============================================
// 1. CREATE A BUCKET (Server-side only)
// ============================================
// Note: Bucket creation requires an API key and must be done server-side
// You would typically do this once during setup or via the Appwrite Console

// Server-side code (Node.js/Deno):
import { Client, Storage, ID, Permission, Role } from 'node-appwrite';

const serverClient = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject(process.env.APPWRITE_PROJECT_ID)
    .setKey(process.env.APPWRITE_API_KEY); // Requires API key

const serverStorage = new Storage(serverClient);

async function createBucket() {
    const bucket = await serverStorage.createBucket(
        ID.unique(),                    // bucketId
        'My Images Bucket',             // name
        [
            Permission.read(Role.any()),           // Anyone can read
            Permission.create(Role.user('[USER_ID]')), // Specific user can upload
            Permission.update(Role.user('[USER_ID]')),
            Permission.delete(Role.user('[USER_ID]')),
        ],
        false,                          // fileSecurity (false = use bucket permissions)
        true,                           // enabled
        10485760,                       // maximumFileSize (10MB)
        ['jpg', 'png', 'gif', 'webp'],  // allowedFileExtensions
        'gzip'                          // compression
    );

    console.log('Bucket created:', bucket);
    return bucket.$id;
}

// ============================================
// 2. UPLOAD A FILE (Client-side)
// ============================================

async function uploadFile(bucketId: string, fileInput: HTMLInputElement) {
    const file = fileInput.files?.[0];

    if (!file) {
        throw new Error('No file selected');
    }

    try {
        const uploadedFile = await storage.createFile({
            bucketId: bucketId,
            fileId: ID.unique(),
            file: file,
            permissions: [
                Permission.read(Role.any()),              // Publicly readable
                Permission.update(Role.user('[USER_ID]')), // Only creator can update
                Permission.delete(Role.user('[USER_ID]')), // Only creator can delete
            ]
        });

        console.log('File uploaded:', uploadedFile);
        return uploadedFile.$id;
    } catch (error) {
        console.error('Upload failed:', error);
        throw error;
    }
}

// ============================================
// 3. GET PREVIEW URL FOR IMAGE
// ============================================

function getImagePreviewUrl(bucketId: string, fileId: string): string {
    // getFilePreview returns a URL object that can be used directly
    const preview = storage.getFilePreview({
        bucketId: bucketId,
        fileId: fileId,
        width: 800,           // Optional: resize width
        height: 600,          // Optional: resize height
        gravity: 'center',    // Optional: crop gravity
        quality: 80,          // Optional: image quality (1-100)
        borderWidth: 2,       // Optional: border width
        borderColor: 'ffffff', // Optional: border color
        borderRadius: 10,     // Optional: border radius
        opacity: 100,         // Optional: opacity (0-100)
        rotation: 0,          // Optional: rotation degrees
        background: 'ffffff', // Optional: background color
        output: 'jpg'         // Optional: output format
    });

    // The result is a URL object - convert to string for use
    return preview.toString();
}

// ============================================
// COMPLETE EXAMPLE: All together
// ============================================

async function main() {
    const BUCKET_ID = '[YOUR_BUCKET_ID]'; // Use existing bucket or create one

    // Get file input element
    const fileInput = document.getElementById('file-input') as HTMLInputElement;

    // Upload the file
    const fileId = await uploadFile(BUCKET_ID, fileInput);

    // Get preview URL
    const previewUrl = getImagePreviewUrl(BUCKET_ID, fileId);

    // Display the preview
    const img = document.createElement('img');
    img.src = previewUrl;
    img.alt = 'Uploaded image preview';
    document.body.appendChild(img);

    console.log('Preview URL:', previewUrl);
}

// ============================================
// HELPER: Display preview in HTML
// ============================================

function displayImagePreview(bucketId: string, fileId: string, containerId: string) {
    const previewUrl = storage.getFilePreview({
        bucketId: bucketId,
        fileId: fileId,
        width: 400,
        height: 300,
        quality: 90
    }).toString();

    const container = document.getElementById(containerId);
    if (container) {
        container.innerHTML = `<img src="${previewUrl}" alt="Preview" style="max-width: 100%;" />`;
    }
}
```

## HTML Example

```html
