## Key Points

1. **Bucket Creation**: Requires server-side SDK with API key - can't be done from client-side for security
2. **Permissions**: Use `Permission` and `Role` helpers to configure access control
3. **Preview URL**: `getFilePreview()` returns a URL object that can be used directly in `<img>` tags
4. **File Input**: Use `document.getElementById('file-input').files[0]` to get the file from an input element

## Common Permission Patterns

```typescript
// Public read, owner-only modifications
permissions: [
    Permission.read(Role.any()),
    Permission.update(Role.user(userId)),
    Permission.delete(Role.user(userId))
]

// Team-based access
permissions: [
    Permission.read(Role.team(teamId)),
    Permission.update(Role.team(teamId, 'admin')),
    Permission.delete(Role.team(teamId, 'admin'))
]

// Private to specific user
permissions: [
    Permission.read(Role.user(userId)),
    Permission.update(Role.user(userId)),
    Permission.delete(Role.user(userId))
]
```

## `getFilePreview` vs `getFileView`

Use **`getFilePreview`** when you need to display an image with transformations (thumbnails, resized versions, cropped images). Use **`getFileView`** when you need the original, unmodified file.

### Key Differences

| Method | Purpose | Use Case |
|--------|---------|----------|
| `getFilePreview` | Returns a **transformed** image | Thumbnails, avatars, resized images, cropped previews |
| `getFileView` | Returns the **original** file | Downloads, displaying full-resolution images, non-image files |

### What `getFilePreview` Supports

`getFilePreview` supports on-the-fly image transformations:

```typescript
const preview = storage.getFilePreview({
    bucketId: '[BUCKET_ID]',
    fileId: '[FILE_ID]',
    width: 300,           // Resize width in pixels
    height: 200,          // Resize height in pixels
    quality: 80,          // Image quality (1-100)
    gravity: 'center',    // Crop gravity: 'center', 'top-left', 'top', 'top-right', etc.
    opacity: 100,         // Opacity (0-100)
    rotation: 0,          // Rotation in degrees (0, 90, 180, 270)
    background: 'ffffff', // Background color (hex without #)
    borderRadius: 10,     // Rounded corners in pixels
    borderWidth: 2,       // Border width in pixels
    borderColor: '000000' // Border color (hex without #)
});
```

### Example: Creating a Thumbnail

```typescript
// Get a 200x200 thumbnail for an avatar
const avatarThumbnail = storage.getFilePreview({
    bucketId: 'avatars',
    fileId: '[FILE_ID]',
    width: 200,
    height: 200,
    quality: 85
});

// Use in an <img> tag
const img = document.createElement('img');
img.src = avatarThumbnail; // Returns a URL string
```

### Example: Getting Original File

```typescript
// Get the original file for download or full display
const originalFile = storage.getFileView({
    bucketId: '[BUCKET_ID]',
    fileId: '[FILE_ID]'
});

// For downloads
const downloadUrl = storage.getFileDownload({
    bucketId: '[BUCKET_ID]',
    fileId: '[FILE_ID]'
});
```

**Note:** `getFilePreview` only works for image files. For non-image files (PDFs, videos, etc.), use `getFileView` or `getFileDownload`.

Here's how to subscribe to both document changes and file uploads simultaneously using the Appwrite Web SDK:

```typescript
import { Client, Realtime, Channel } from 'appwrite';

// Initialize the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

// Create realtime instance
const realtime = new Realtime(client);

// Subscribe to both document changes and file uploads
const subscription = await realtime.subscribe(
    [
        // All rows in a table
        Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
        // All files in a bucket
        Channel.bucket('[BUCKET_ID]').file(),
    ],
    (response) => {
        // Check which type of event occurred
        const isDocumentEvent = response.events.some(event => 
            event.includes('tablesdb') && event.includes('rows')
        );
        const isFileEvent = response.events.some(event => 
            event.includes('buckets') && event.includes('files')
        );

        // Handle document changes
        if (isDocumentEvent) {
            handleDocumentChange(response);
        }

        // Handle file uploads
        if (isFileEvent) {
            handleFileChange(response);
        }
    }
);

// Document event handler
function handleDocumentChange(response: any) {
    const event = response.events[0];
    const doc = response.payload;

    // Determine the specific action
    if (event.includes('.create')) {
        console.log('📄 Document created:', doc.$id);
        console.log('   Data:', doc);
        // Update UI, show notification, etc.
    } else if (event.includes('.update')) {
        console.log('📝 Document updated:', doc.$id);
        console.log('   Updated data:', doc);
        // Sync local state, etc.
    } else if (event.includes('.delete')) {
        console.log('🗑️ Document deleted:', doc.$id);
        // Remove from local state, etc.
    }
}

// File event handler
function handleFileChange(response: any) {
    const event = response.events[0];
    const file = response.payload;

    // Determine the specific action
    if (event.includes('.create')) {
        console.log('📁 File uploaded:', file.name);
        console.log('   File ID:', file.$id);
        console.log('   Size:', file.sizeOriginal, 'bytes');
        console.log('   MIME type:', file.mimeType);
        // Update file list, show preview, etc.
    } else if (event.includes('.update')) {
        console.log('✏️ File updated:', file.name);
        // Refresh file metadata, etc.
    } else if (event.includes('.delete')) {
        console.log('🗑️ File deleted:', file.$id);
        // Remove from UI, cleanup references, etc.
    }
}

// Later, when you want to stop listening
async function cleanup() {
    await subscription.close();
    console.log('Unsubscribed from all channels');
}
```

## Alternative: Separate Subscriptions for More Control

If you need completely independent handling logic:

```typescript
// Subscribe to document changes
const docSubscription = await realtime.subscribe(
    Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
    (response) => {
        console.log('Document event:', response.events);
        console.log('Payload:', response.payload);
        console.log('Timestamp:', response.timestamp);
    }
);

// Subscribe to file uploads
const fileSubscription = await realtime.subscribe(
    Channel.bucket('[BUCKET_ID]').file(),
    (response) => {
        console.log('File event:', response.events);
        console.log('Payload:', response.payload);
        console.log('Timestamp:', response.timestamp);
    }
);

// Unsubscribe individually
await docSubscription.close();
await fileSubscription.close();
```

## Key Points

| Aspect | Details |
|--------|---------|
| **Channel Builder** | Use `Channel` helper for type-safe channel strings |
| **Multiple Channels** | Pass an array to subscribe to multiple resources at once |
| **Event Detection** | Check `response.events` array to determine event type |
| **Payload** | `response.payload` contains the affected document or file object |
| **Cleanup** | Always call `subscription.close()` to prevent memory leaks |

The `response.events` array contains strings like:
- `tablesdb.[DB_ID].tables.[TABLE_ID].rows.[ROW_ID].create`
- `buckets.[BUCKET_ID].files.[FILE_ID].create`

Here's a single `subscribe()` call listening to both channels:

```typescript
import { Client, Realtime, Channel } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const realtime = new Realtime(client);

// Subscribe to both database rows and storage files
const subscription = await realtime.subscribe([
    Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
    Channel.bucket('[BUCKET_ID]').file(),
], (response) => {
    console.log(response.events);   // e.g. ['tablesdb.*.tables.*.rows.*.create'] or ['buckets.*.files.*.create']
    console.log(response.payload);  // the affected document or file
});
```

## Exact Channel Strings

| Resource | Channel String |
|----------|----------------|
| All rows in a table | `tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows` |
| A specific row | `tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows.[ROW_ID]` |
| All files in a bucket | `buckets.[BUCKET_ID].files` |
| A specific file | `buckets.[BUCKET_ID].files.[FILE_ID]` |

## Unsubscribe

```typescript
await subscription.close();
```

Here’s a minimal **Appwrite Web SDK** example for email/password signup and login.

```ts
// auth.ts (or auth.js)
import { Client, Account, ID, AppwriteException } from "appwrite";

// 1) Set up Appwrite client
const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1") // e.g. https://eu-west.cloud.appwrite.io/v1
  .setProject("<PROJECT_ID>");

const account = new Account(client);

// 2) Create an account (signup)
export async function signUp(email: string, password: string, name?: string) {
  try {
    const user = await account.create({
      userId: ID.unique(),
      email,
      password,
      name,
    });

    // 3) Create a session after signup (auto-login)
    const session = await account.createEmailPasswordSession({
      email,
      password,
    });

    return { user, session };
  } catch (err) {
    if (err instanceof AppwriteException) {
      console.error("Signup error:", err.message, err.code);
    }
    throw err;
  }
}

// Login (create session for existing user)
export async function logIn(email: string, password: string) {
  try {
    return await account.createEmailPasswordSession({
      email,
      password,
    });
  } catch (err) {
    if (err instanceof AppwriteException) {
      console.error("Login error:", err.message, err.code);
    }
    throw err;
  }
}
```

