Here’s a Web SDK example using the current **TablesDB API** (table/row = collection/document equivalent):

```ts
import { Client, TablesDB, ID } from 'appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>');

const tablesDB = new TablesDB(client);

async function createTasksSchemaAndInsert() {
  // 1) Create database
  const database = await tablesDB.create({
    databaseId: ID.unique(),
    name: 'My Database',
  });

  // 2) Create "tasks" collection (table) with attributes (columns)
  await tablesDB.createTable({
    databaseId: database.$id,
    tableId: 'tasks',
    name: 'Tasks',
    columns: [
      { key: 'title', type: 'varchar', size: 255, required: true }, // string
      { key: 'completed', type: 'boolean', required: true },         // boolean
      { key: 'dueDate', type: 'datetime', required: false },         // datetime
    ],
  });

  // 3) Insert a document (row)
  const task = await tablesDB.createRow({
    databaseId: database.$id,
    tableId: 'tasks',
    rowId: ID.unique(),
    data: {
      title: 'Finish Appwrite setup',
      completed: false,
      dueDate: new Date('2026-12-31T23:59:59.000Z').toISOString(),
    },
  });

  console.log('Inserted task:', task);
}

createTasksSchemaAndInsert().catch(console.error);
```

