```ts
// appwrite-storage-example.ts
// Uses Appwrite Web SDK (`appwrite`)
// NOTE: Creating a bucket is an admin action. Run `ensureBucket()` in a trusted server context only.

import {
  Client,
  Storage,
  Account,
  ID,
  Permission,
  Role,
  AppwriteException,
} from "appwrite";

const ENDPOINT = "https://<REGION>.cloud.appwrite.io/v1";
const PROJECT_ID = "<PROJECT_ID>";
const BUCKET_ID = "images";

// ------------------------------
// 1) Admin: Create bucket (run once, server-side only)
// ------------------------------
const adminClient = new Client()
  .setEndpoint(ENDPOINT)
  .setProject(PROJECT_ID)
  .setKey(process.env.APPWRITE_API_KEY!); // NEVER expose this in browser

const adminStorage = new Storage(adminClient);

export async function ensureBucket() {
  try {
    await adminStorage.createBucket({
      bucketId: BUCKET_ID,
      name: "Images",
      fileSecurity: true, // enables per-file permissions
      permissions: [
        Permission.read(Role.users()),   // authenticated users can read/list
        Permission.create(Role.users()), // authenticated users can upload
      ],
      allowedFileExtensions: ["jpg", "jpeg", "png", "webp"],
      maximumFileSize: 10 * 1024 * 1024, // 10MB
    });
  } catch (err) {
    // Ignore "already exists"
    if (!(err instanceof AppwriteException) || err.code !== 409) throw err;
  }
}

// ------------------------------
// 2) Browser: Upload image + get preview URL
// ------------------------------
const client = new Client().setEndpoint(ENDPOINT).setProject(PROJECT_ID);
const storage = new Storage(client);
const account = new Account(client);

export async function uploadImageAndGetPreview(file: File): Promise<string> {
  if (!file.type.startsWith("image/")) {
    throw new Error("Please upload an image file.");
  }

  // Requires user to be logged in
  const me = await account.get();

  const uploaded = await storage.createFile({
    bucketId: BUCKET_ID,
    fileId: ID.unique(),
    file,
    permissions: [
      Permission.read(Role.any()), // public preview/read
      Permission.update(Role.user(me.$id)),
      Permission.delete(Role.user(me.$id)),
    ],
  });

  const previewUrl = storage.getFilePreview({
    bucketId: BUCKET_ID,
    fileId: uploaded.$id,
    width: 800,
    height: 800,
    quality: 80,
  });

  return previewUrl.toString();
}
```

