Absolutely—here’s a Web SDK example that listens to **table row changes** and **bucket file uploads** at the same time, then routes each event type to different handlers.

```ts
import { Client, Realtime, Channel } from 'appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>');

const realtime = new Realtime(client);

const DATABASE_ID = '<DATABASE_ID>';
const TABLE_ID = '<TABLE_ID>';
const BUCKET_ID = '<BUCKET_ID>';

// Subscribe to both channels in one realtime subscription
const subscription = await realtime.subscribe(
  [
    Channel.tablesdb(DATABASE_ID).table(TABLE_ID).row(), // row create/update/delete
    Channel.bucket(BUCKET_ID).file(),                    // file create/update/delete
  ],
  (message) => {
    const events = message.events ?? [];

    const isRowEvent = events.some((e) => e.includes('.rows.'));
    const isFileEvent = events.some((e) => e.includes('.files.'));

    if (isRowEvent) {
      handleRowEvent(events, message.payload);
      return;
    }

    if (isFileEvent) {
      handleFileEvent(events, message.payload);
    }
  }
);

function handleRowEvent(events: string[], row: any) {
  if (events.some((e) => e.endsWith('.create'))) {
    console.log('🟢 Row created:', row.$id, row);
  } else if (events.some((e) => e.endsWith('.update'))) {
    console.log('🟡 Row updated:', row.$id, row);
  } else if (events.some((e) => e.endsWith('.delete'))) {
    console.log('🔴 Row deleted:', row.$id);
  }
}

function handleFileEvent(events: string[], file: any) {
  if (events.some((e) => e.endsWith('.create'))) {
    // File "create" == new upload
    console.log('📦 File uploaded:', file.$id, file.name);
  } else if (events.some((e) => e.endsWith('.update'))) {
    console.log('✏️ File updated:', file.$id);
  } else if (events.some((e) => e.endsWith('.delete'))) {
    console.log('🗑️ File deleted:', file.$id);
  }
}

// Cleanup when leaving the page/component
// await subscription.close();
```

> Note: realtime only delivers events the current user has permission to read (rows/files).

