Here’s a Web SDK example that listens to both database row changes (document-like records) and bucket file events in one realtime subscription, then handles them differently.

```ts
import { Client, Realtime, Channel } from 'appwrite';

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('<PROJECT_ID>');

const realtime = new Realtime(client);

const databaseId = '<DATABASE_ID>';
const tableId = '<TABLE_ID>';
const bucketId = '<BUCKET_ID>';

function handleDocumentChange(events: string[], payload: any) {
  if (events.some((event) => event.endsWith('.create'))) {
    console.log('Document created:', payload);
    // Example: add the new document to your UI
    return;
  }

  if (events.some((event) => event.endsWith('.update'))) {
    console.log('Document updated:', payload);
    // Example: update an existing UI item
    return;
  }

  if (events.some((event) => event.endsWith('.delete'))) {
    console.log('Document deleted:', payload);
    // Example: remove the document from your UI
  }
}

function handleFileEvent(events: string[], payload: any) {
  // Treat file "create" as a new upload
  if (events.some((event) => event.endsWith('.create'))) {
    console.log('File uploaded:', payload);
    // Example: show a toast or append the file to a gallery
    return;
  }

  // Optional: handle other file events differently
  if (events.some((event) => event.endsWith('.update'))) {
    console.log('File updated:', payload);
    return;
  }

  if (events.some((event) => event.endsWith('.delete'))) {
    console.log('File deleted:', payload);
  }
}

async function startRealtime() {
  const subscription = await realtime.subscribe(
    [
      Channel.tablesdb(databaseId).table(tableId).row(),
      Channel.bucket(bucketId).file(),
    ],
    (response) => {
      const { events, payload } = response;

      const isDocumentEvent = events.some((event) => event.includes('.rows.'));
      const isFileEvent = events.some((event) => event.includes('.files.'));

      if (isDocumentEvent) {
        handleDocumentChange(events, payload);
        return;
      }

      if (isFileEvent) {
        handleFileEvent(events, payload);
      }
    }
  );

  return subscription;
}

const subscription = await startRealtime();

// Later, when cleaning up:
// await subscription.close();
```

Notes:
- `Channel.tablesdb(...).table(...).row()` listens for all row changes in a table.
- `Channel.bucket(...).file()` listens for all file events in a bucket.
- A file upload shows up as a `.create` file event.
- The logged-in user must have `read` permission for the rows/files to receive realtime events.

