Here's a complete implementation of **email/password signup and login** using the Appwrite Web SDK:

---

## 1. Install the SDK

```bash
npm install appwrite
```

## 2. Set Up the Appwrite Client

Create a reusable client configuration file:

```typescript
// src/appwrite.ts
import { Client, Account, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('[PROJECT_ID]');                           // Your project ID

const account = new Account(client);

export { client, account, ID };
```

## 3. Sign Up (Create an Account)

```typescript
// src/auth/signup.ts
import { account, ID } from '../appwrite';
import { AppwriteException } from 'appwrite';

async function signup(email: string, password: string, name: string) {
    try {
        // Step 1: Create the user account
        const newUser = await account.create({
            userId: ID.unique(),
            email,
            password,
            name,
        });
        console.log('Account created:', newUser.$id);

        // Step 2: Immediately log them in by creating a session
        const session = await account.createEmailPasswordSession({
            email,
            password,
        });
        console.log('Session created:', session.$id);

        // Step 3: Fetch the authenticated user's profile
        const user = await account.get();
        console.log('Logged in as:', user.name, user.email);

        return user;
    } catch (err) {
        if (err instanceof AppwriteException) {
            switch (err.code) {
                case 409:
                    console.error('A user with this email already exists.');
                    break;
                case 429:
                    console.error('Too many requests. Please try again later.');
                    break;
                default:
                    console.error(`Signup failed [${err.code}]: ${err.message}`);
            }
        }
        throw err;
    }
}
```

## 4. Log In (Create a Session)

```typescript
// src/auth/login.ts
import { account } from '../appwrite';
import { AppwriteException } from 'appwrite';

async function login(email: string, password: string) {
    try {
        // Create an email/password session
        const session = await account.createEmailPasswordSession({
            email,
            password,
        });
        console.log('Session created:', session.$id);

        // Fetch the authenticated user's profile
        const user = await account.get();
        console.log('Logged in as:', user.name, user.email);

        return user;
    } catch (err) {
        if (err instanceof AppwriteException) {
            switch (err.code) {
                case 401:
                    console.error('Invalid email or password.');
                    break;
                case 429:
                    console.error('Too many attempts. Please try again later.');
                    break;
                default:
                    console.error(`Login failed [${err.code}]: ${err.message}`);
            }
        }
        throw err;
    }
}
```

## 5. Log Out (Delete the Session)

```typescript
// src/auth/logout.ts
import { account } from '../appwrite';

async function logout() {
    // Destroy the current session
    await account.deleteSession({ sessionId: 'current' });
    console.log('Logged out successfully.');
}
```

## 6. Get the Current User

```typescript
// src/auth/getUser.ts
import { account } from '../appwrite';
import { AppwriteException } from 'appwrite';

async function getCurrentUser() {
    try {
        const user = await account.get();
        return user;
    } catch (err) {
        if (err instanceof AppwriteException && err.code === 401) {
            // No active session — user is not logged in
            return null;
        }
        throw err;
    }
}
```

## 7. Putting It All Together

```typescript
// src/main.ts
import { signup, login, logout, getCurrentUser } from './auth';

// Sign up a new user
await signup('alice@example.com', 'securePassword123', 'Alice');

// Log out
await logout();

// Log back in
await login('alice@example.com', 'securePassword123');

// Check who's logged in
const user = await getCurrentUser();
if (user) {
    console.log(`Welcome back, ${user.name}!`);
} else {
    console.log('No active session.');
}
```

---

### Key Points

| Concept | Detail |
|---|---|
| **`account.create()`** | Registers a new user but does **not** create a session — the user is not logged in yet. |
| **`account.createEmailPasswordSession()`** | Authenticates the user and creates a session (stored as a cookie in the browser). |
| **`account.get()`** | Returns the currently authenticated user. Throws `401` if no session exists. |
| **`account.deleteSession({ sessionId: 'current' })`** | Destroys the active session (logout). |
| **`ID.unique()`** | Generates a unique ID for the new user. You can also pass your own custom ID string. |
| **Password requirements** | Passwords must be between 8 and 256 characters long. |

## `account.deleteSession()` vs `account.deleteSessions()`

These two methods serve different purposes in Appwrite's session management. Here's a clear breakdown:

---

### `account.deleteSession({ sessionId })`

**What it does:** Deletes a **single, specific** session for the currently authenticated user.

```typescript
const account = new Account(client);

// Log out of the CURRENT session only
await account.deleteSession({ sessionId: 'current' });

// Log out of a SPECIFIC session by its ID
await account.deleteSession({ sessionId: '64a1b2c3d4e5f6...' });
```

**When to use it:**
- **Standard logout** — Pass `'current'` as the `sessionId` to end the user's current session (the most common logout pattern).
- **Revoking a specific device** — If a user is logged in on multiple devices and wants to log out of just one (e.g., "Log out of my phone"), you'd pass that session's specific ID.
- **Security response** — If you detect suspicious activity on one particular session, you can revoke just that one.

---

### `account.deleteSessions()`

**What it does:** Deletes **all** sessions for the currently authenticated user — across every device and browser.

```typescript
const account = new Account(client);

// Log out of ALL sessions everywhere
await account.deleteSessions();
```

**When to use it:**
- **"Log out everywhere"** — A common security feature where the user wants to terminate all active sessions at once (e.g., after changing their password or suspecting their account was compromised).
- **Account security reset** — After a password change or security incident, force-logout from all devices to ensure only the new credentials can be used.
- **Account deactivation flows** — Before deactivating or deleting an account, clear all sessions.

---

### Summary Table

| Feature | `deleteSession({ sessionId })` | `deleteSessions()` |
|---|---|---|
| **Scope** | One specific session | All sessions for the user |
| **Common use** | Standard logout (`'current'`) or revoking a single device | "Log out everywhere" |
| **Parameter** | `sessionId` (use `'current'` or a specific ID) | None |
| **Typical trigger** | "Log out" button | "Log out of all devices" button, post-password-change |

### Practical Example

```typescript
const account = new Account(client);

// Normal logout — ends only the current session
async function logout() {
    await account.deleteSession({ sessionId: 'current' });
}

// Security logout — ends ALL sessions everywhere
async function logoutEverywhere() {
    await account.deleteSessions();
}
```

> **Tip:** In most apps, you'll use `deleteSession({ sessionId: 'current' })` for the standard "Log out" button, and reserve `deleteSessions()` for a dedicated "Log out of all devices" option in your security settings page.

Here's a complete example using the **Appwrite Server SDK** (`node-appwrite`) to create a database, a "tasks" collection with attributes, and insert a document:

## Setup & Installation

```bash
npm install node-appwrite
```

## Full Code

```typescript
import { Client, TablesDB, ID } from 'node-appwrite';

// --- 1. Initialize the Admin Client ---
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject(process.env.APPWRITE_PROJECT_ID!)          // Your project ID
    .setKey(process.env.APPWRITE_API_KEY!);                // API key with databases.* scopes

const tablesDB = new TablesDB(client);

async function main() {
    try {
        // --- 2. Create the Database ---
        const database = await tablesDB.create({
            databaseId: ID.unique(),
            name: 'TaskManager',
        });
        console.log('✅ Database created:', database.$id);

        const databaseId = database.$id;

        // --- 3. Create the "tasks" Collection (Table) ---
        // We define all columns inline when creating the table.
        const tasksTable = await tablesDB.createTable({
            databaseId,
            tableId: ID.unique(),
            name: 'tasks',
            columns: [
                {
                    key: 'title',
                    type: 'varchar',
                    size: 255,
                    required: true,
                },
                {
                    key: 'completed',
                    type: 'boolean',
                    required: true,
                },
                {
                    key: 'dueDate',
                    type: 'datetime',
                    required: false,
                },
            ],
        });
        console.log('✅ Tasks table created:', tasksTable.$id);

        const tableId = tasksTable.$id;

        // --- 4. Insert a Document (Row) ---
        const task = await tablesDB.createRow({
            databaseId,
            tableId,
            rowId: ID.unique(),
            data: {
                title: 'Finish project proposal',
                completed: false,
                dueDate: '2025-02-15T17:00:00.000+00:00', // ISO 8601 format
            },
        });
        console.log('✅ Task created:', task);

        // --- 5. Insert a few more tasks ---
        const task2 = await tablesDB.createRow({
            databaseId,
            tableId,
            rowId: ID.unique(),
            data: {
                title: 'Review pull requests',
                completed: true,
                dueDate: '2025-01-20T09:00:00.000+00:00',
            },
        });
        console.log('✅ Task created:', task2.$id);

        const task3 = await tablesDB.createRow({
            databaseId,
            tableId,
            rowId: ID.unique(),
            data: {
                title: 'Deploy to production',
                completed: false,
                dueDate: null, // no due date
            },
        });
        console.log('✅ Task created:', task3.$id);

        // --- 6. List all tasks ---
        const allTasks = await tablesDB.listRows({
            databaseId,
            tableId,
        });
        console.log(`\n📋 All tasks (${allTasks.total}):`);
        allTasks.documents.forEach((doc) => {
            console.log(
                `  - [${doc.completed ? '✓' : ' '}] ${doc.title} (due: ${doc.dueDate ?? 'N/A'})`
            );
        });

    } catch (err) {
        console.error('❌ Error:', err);
    }
}

main();
```

## Key Points

| Concept | Detail |
|---|---|
| **`TablesDB`** | The current class for all database operations (replaces the deprecated `Databases` class). |
| **`createTable` with `columns`** | Attributes are defined inline as `columns` when creating the table — no separate attribute creation calls needed. |
| **Column types** | `varchar` for short indexed strings, `boolean` for true/false, `datetime` for ISO 8601 timestamps. |
| **`ID.unique()`** | Generates a unique ID server-side for databases, tables, and rows. |
| **`dueDate` format** | Datetime fields must use **ISO 8601** format (e.g., `2025-02-15T17:00:00.000+00:00`). |
| **Server-side only** | Creating databases, tables, and defining columns requires the **server SDK** (`node-appwrite`) with an API key. Client-side SDKs can only read/write rows. |

> **⚠️ Permissions:** The rows above have no explicit permissions set, so they'll only be accessible via the server SDK (with an API key). To make them accessible to client-side users, pass a `permissions` array when creating each row:
> ```typescript
> permissions: [
>     Permission.read(Role.any()),           // anyone can read
>     Permission.update(Role.users()),       // any logged-in user can update
> ]
> ```

# Querying Documents in Appwrite with the `Query` Class

Appwrite provides a powerful `Query` class that lets you filter, sort, paginate, and select fields when listing documents. Here's a comprehensive guide with examples.

---

## Setup

```typescript
import { Client, TablesDB, Query } from 'appwrite';
// Server-side: import from 'node-appwrite'

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);
```

---

## 1. Filtering

Filters are passed as an array of `Query` expressions to the `queries` parameter. **By default, all queries are combined with AND logic.**

### Basic Equality & Inequality

```typescript
// Exact match
const active = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.equal('status', 'active')]
});

// Not equal
const incomplete = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.notEqual('status', 'done')]
});

// IN — match any value in an array
const filtered = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.equal('priority', ['high', 'critical'])]
});
```

### Comparison Operators

```typescript
// Greater than / less than
Query.greaterThan('price', 100)       // price > 100
Query.greaterThanEqual('price', 100)  // price >= 100
Query.lessThan('price', 500)          // price < 500
Query.lessThanEqual('price', 500)     // price <= 500

// Between (inclusive on both ends)
Query.between('price', 100, 500)      // 100 <= price <= 500
```

### Null Checks

```typescript
Query.isNull('deletedAt')       // field is null
Query.isNotNull('assignee')     // field is not null
```

### String Matching

```typescript
Query.startsWith('email', 'john')       // starts with "john"
Query.endsWith('email', '@gmail.com')   // ends with "@gmail.com"
Query.contains('tags', 'urgent')        // string/array contains "urgent"
Query.search('content', 'hello world')  // full-text search (requires a full-text index!)
```

### Combining Multiple Filters (AND)

By default, all queries in the array are **ANDed** together:

```typescript
const results = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        Query.equal('status', 'active'),
        Query.greaterThan('priority', 3),
        Query.isNotNull('assignee')
    ]
});
// → status == 'active' AND priority > 3 AND assignee IS NOT NULL
```

### OR Logic

Use `Query.or()` to combine conditions with OR:

```typescript
const results = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        Query.or([
            Query.equal('status', 'active'),
            Query.equal('status', 'pending')
        ])
    ]
});
// → status == 'active' OR status == 'pending'
```

### Combining AND + OR

```typescript
const results = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        Query.greaterThan('priority', 3),                          // AND
        Query.or([                                                  // (status = 'active' OR status = 'pending')
            Query.equal('status', 'active'),
            Query.equal('status', 'pending')
        ])
    ]
});
// → priority > 3 AND (status == 'active' OR status == 'pending')
```

---

## 2. Sorting

Use `orderAsc` and `orderDesc` to sort results:

```typescript
// Sort by creation date, newest first
const newest = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.orderDesc('$createdAt')]
});

// Sort by priority ascending, then by title ascending
const sorted = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        Query.orderAsc('priority'),
        Query.orderAsc('title')
    ]
});
```

> **Tip:** You can sort by built-in fields like `$createdAt` and `$updatedAt`.

---

## 3. Limiting Results

```typescript
// Return only 10 results (default is 25, max is 100)
const limited = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.limit(10)]
});
```

---

## 4. Pagination

### Offset-Based Pagination (simple, but slower for large datasets)

```typescript
// Page 1
const page1 = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.limit(25), Query.offset(0)]
});

// Page 2
const page2 = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.limit(25), Query.offset(25)]
});

// Page 3
const page3 = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.limit(25), Query.offset(50)]
});
```

### Cursor-Based Pagination (preferred for large datasets)

Uses the last document's `$id` to fetch the next page — more efficient than offset:

```typescript
// First page
const page1 = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [Query.limit(25), Query.orderDesc('$createdAt')]
});

// Next page — pass the last document's ID
const lastDoc = page1.documents[page1.documents.length - 1];
const page2 = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        Query.limit(25),
        Query.orderDesc('$createdAt'),
        Query.cursorAfter(lastDoc.$id)
    ]
});

// Previous page — use cursorBefore with the first document's ID
const firstDoc = page2.documents[0];
const prevPage = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        Query.limit(25),
        Query.orderDesc('$createdAt'),
        Query.cursorBefore(firstDoc.$id)
    ]
});
```

> **Tip:** The response includes a `total` field with the total count of matching documents, useful for displaying "Page X of Y".

---

## 5. Field Selection

Return only specific fields to reduce payload size:

```typescript
const results = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        Query.select(['title', 'status', 'priority']),
        Query.limit(50)
    ]
});
```

---

## 6. Putting It All Together

Here's a real-world example combining filtering, sorting, pagination, and selection:

```typescript
const results = await tablesDB.listRows({
    databaseId: 'mydb',
    tableId: 'tasks',
    queries: [
        // Filter: active tasks with high priority
        Query.equal('status', 'active'),
        Query.greaterThanEqual('priority', 4),
        Query.isNotNull('assignee'),

        // Sort: newest first
        Query.orderDesc('$createdAt'),

        // Paginate: 10 per page, cursor-based
        Query.limit(10),
        Query.cursorAfter('[LAST_DOC_ID]'),

        // Select: only return needed fields
        Query.select(['title', 'priority', 'assignee', '$createdAt'])
    ]
});

console.log(`Total matching: ${results.total}`);
console.log(`Returned: ${results.documents.length}`);
results.documents.forEach(doc => {
    console.log(`${doc.title} — Priority: ${doc.priority} — Assigned: ${doc.assignee}`);
});
```

---

## Quick Reference Table

| Category | Method | Description |
|----------|--------|-------------|
| **Equality** | `Query.equal(field, value)` | Exact match (or IN with array) |
| | `Query.notEqual(field, value)` | Not equal |
| **Comparison** | `Query.greaterThan(field, val)` | `>` |
| | `Query.greaterThanEqual(field, val)` | `>=` |
| | `Query.lessThan(field, val)` | `<` |
| | `Query.lessThanEqual(field, val)` | `<=` |
| | `Query.between(field, min, max)` | Inclusive range |
| **Null** | `Query.isNull(field)` | Is null |
| | `Query.isNotNull(field)` | Is not null |
| **String** | `Query.startsWith(field, prefix)` | Starts with |
| | `Query.endsWith(field, suffix)` | Ends with |
| | `Query.contains(field, val)` | Contains value |
| | `Query.search(field, keywords)` | Full-text search |
| **Sorting** | `Query.orderAsc(field)` | Ascending sort |
| | `Query.orderDesc(field)` | Descending sort |
| **Pagination** | `Query.limit(n)` | Max results (default 25, max 100) |
| | `Query.offset(n)` | Skip N results |
| | `Query.cursorAfter(docId)` | After document ID |
| | `Query.cursorBefore(docId)` | Before document ID |
| **Selection** | `Query.select([fields])` | Return only listed fields |
| **Logical** | `Query.or([...queries])` | OR condition |
| | `Query.and([...queries])` | Explicit AND |

> ⚠️ **Important:** String search methods like `startsWith`, `endsWith`, and `contains` require appropriate indexes on the attribute. `Query.search()` specifically requires a **full-text index** to be configured on the attribute.

## Filtering, Sorting & Limiting with `Query`

Here's how to filter documents where a numeric field (e.g., `score`) is **greater than 100**, **limit** results to **20**, and **sort descending** by that field.

---

### Step-by-Step Breakdown

#### 1. Import `Query`

```typescript
// Client-side (Web)
import { Query } from 'appwrite';

// Server-side (Node.js / Deno)
import { Query } from 'node-appwrite';
```

#### 2. Build the Query Array

You combine multiple `Query` methods into a single `queries` array. All conditions in the array are **AND-ed** together by default.

```typescript
const queries = [
  Query.greaterThan('score', 100),   // Only rows where score > 100
  Query.orderDesc('score'),          // Sort by score descending (highest first)
  Query.limit(20),                   // Return at most 20 results
];
```

#### 3. Pass Queries to `listRows`

```typescript
const tablesDB = new TablesDB(client);

const results = await tablesDB.listRows({
  databaseId: '[DATABASE_ID]',
  tableId: '[TABLE_ID]',
  queries: queries,
});

console.log(results.total);      // Total matching documents (may be > 20)
console.log(results.documents);  // Array of up to 20 documents
```

---

### Full Example

```typescript
import { Client, TablesDB, Query } from 'appwrite';
// Server-side: import from 'node-appwrite'

const client = new Client()
  .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
  .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

const results = await tablesDB.listRows({
  databaseId: 'myDatabase',
  tableId: 'leaderboard',
  queries: [
    Query.greaterThan('score', 100),  // filter: score > 100
    Query.orderDesc('score'),         // sort: highest score first
    Query.limit(20),                  // pagination: max 20 results
  ],
});

// Iterate over the results
for (const doc of results.documents) {
  console.log(`${doc.$id}: score = ${doc.score}`);
}
```

---

### Key Query Methods Used

| Method | Purpose | Example |
|--------|---------|---------|
| `Query.greaterThan(field, value)` | Keep rows where `field > value` | `Query.greaterThan('score', 100)` |
| `Query.orderDesc(field)` | Sort results in **descending** order | `Query.orderDesc('score')` |
| `Query.limit(n)` | Cap the number of returned rows (max 100) | `Query.limit(20)` |

### Other Useful Numeric Filters

| Method | Meaning |
|--------|---------|
| `Query.greaterThanEqual('score', 100)` | `score >= 100` |
| `Query.lessThan('score', 100)` | `score < 100` |
| `Query.lessThanEqual('score', 100)` | `score <= 100` |
| `Query.between('score', 50, 200)` | `50 <= score <= 200` |

> **Important:** Make sure the `score` field (or whichever numeric field you're querying) has an **index** created on it in your Appwrite console or via the API. Without an index, filter and sort queries on that field will fail.

Here's a complete Appwrite Function in Node.js that receives a JSON body with a `"name"` field and returns a personalized greeting:

## The Function Code

### `src/main.js`

```javascript
export default async ({ req, res, log, error }) => {
  // Only accept POST requests (since we expect a JSON body)
  if (req.method !== 'POST') {
    return res.json({ error: 'Method not allowed. Please use POST.' }, 405);
  }

  // Parse the JSON body — Appwrite provides `req.bodyJson` automatically
  const body = req.bodyJson;

  // Validate the "name" field exists
  if (!body || !body.name) {
    error('Missing required "name" field in request body.');
    return res.json({ error: '"name" field is required.' }, 400);
  }

  const name = body.name.trim();

  if (name.length === 0) {
    error('"name" field is empty.');
    return res.json({ error: '"name" field must not be empty.' }, 400);
  }

  log(`Generating greeting for: ${name}`);

  // Return the personalized greeting
  return res.json({
    success: true,
    greeting: `Hello, ${name}! Welcome to Appwrite 👋`,
  });
};
```

---

## How It Works

| Concept | Detail |
|---|---|
| **Function signature** | Appwrite Functions export a **default async function** that receives a single context object with `req`, `res`, `log`, and `error`. |
| **`req.bodyJson`** | Appwrite automatically parses JSON request bodies into an object. No need for `JSON.parse()`. |
| **`req.method`** | The HTTP method (`GET`, `POST`, `PUT`, `DELETE`, `PATCH`). We guard for `POST` since we expect a body. |
| **`res.json(data, statusCode)`** | Returns a JSON response with the correct `Content-Type` header. The second argument is an optional HTTP status code. |
| **`log()` / `error()`** | Built-in logging helpers that write to the function's execution logs (visible in the Appwrite Console). |

---

## Example Usage

**Request:**
```bash
curl -X POST https://<REGION>.cloud.appwrite.io/v1/functions/<FUNCTION_ID>/executions \
  -H "Content-Type: application/json" \
  -H "X-Appwrite-Project: <PROJECT_ID>" \
  -d '{"name": "Alice"}'
```

**Response (200):**
```json
{
  "success": true,
  "greeting": "Hello, Alice! Welcome to Appwrite 👋"
}
```

**Error — missing name (400):**
```json
{
  "error": "\"name\" field is required."
}
```

---

## Other Available Response Methods

| Method | Use Case |
|---|---|
| `res.json(obj, status?)` | Return JSON (most common) |
| `res.text('string')` | Return plain text |
| `res.empty()` | Return `204 No Content` |
| `res.redirect('url')` | Return `302 Redirect` |
| `res.send(body, status, headers)` | Full control over body, status, and headers |

This pattern — validate the method, check `req.bodyJson`, return with `res.json()` — is the idiomatic way to write Appwrite Functions in Node.js.

Based on the documentation, here are **three key `APPWRITE_FUNCTION_*` environment variables** available inside an Appwrite Function at runtime:

---

### 1. `APPWRITE_FUNCTION_PROJECT_ID`
- **What it's for:** Contains the **Project ID** of the Appwrite project the function belongs to. This is commonly used when initializing the Appwrite SDK client inside your function so it knows which project to interact with.

### 2. `APPWRITE_FUNCTION_API_KEY`
- **What it's for:** Provides a **scoped API key** that the function can use to authenticate server-side SDK calls. This allows the function to perform privileged/admin operations (e.g., managing users, reading any database document) without you having to hard-code or manually pass an API key. It is typically passed to `client.setKey()`.

### 3. `APPWRITE_FUNCTION_ENDPOINT`
- **What it's for:** Contains the **Appwrite API endpoint URL** (e.g., `https://<REGION>.cloud.appwrite.io/v1`). This is used when setting up the SDK client inside the function via `client.setEndpoint()`, so the function knows where to send API requests.

---

### How They're Used Together

Inside a function handler, these three variables are commonly combined to bootstrap an admin client:

```typescript
import { Client, TablesDB } from 'node-appwrite';

export default async ({ req, res, log, error }) => {
    const client = new Client()
        .setEndpoint(process.env.APPWRITE_FUNCTION_ENDPOINT)
        .setProject(process.env.APPWRITE_FUNCTION_PROJECT_ID)
        .setKey(process.env.APPWRITE_FUNCTION_API_KEY);

    const db = new TablesDB(client);
    // ... perform server-side operations
};
```

> **Tip:** Because these variables are injected automatically by the Appwrite runtime, you never need to configure them manually — they're always available when your function executes.

Here's a complete example using the Appwrite Web SDK to **create a bucket** (server-side), **upload a file** (client-side), and **get a preview URL** for an image — all with proper permission configuration.

---

## Step 1: Create a Bucket (Server-Side with API Key)

Bucket creation requires admin privileges, so this runs on the server using `node-appwrite`:

```typescript
import { Client, Storage, Permission, Role, ID } from 'node-appwrite';

// Admin client with API key
const adminClient = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey(process.env.APPWRITE_API_KEY!);

const adminStorage = new Storage(adminClient);

async function createImageBucket() {
    const bucket = await adminStorage.createBucket({
        bucketId: ID.unique(),
        name: 'Image Uploads',
        permissions: [
            Permission.read(Role.any()),                // Anyone can view/download files
            Permission.create(Role.users()),            // Any authenticated user can upload
            Permission.update(Role.users()),            // Any authenticated user can update their files
            Permission.delete(Role.users()),            // Any authenticated user can delete their files
        ],
        fileSecurity: true,     // Enable file-level permissions (in addition to bucket-level)
        maximumFileSize: 10_000_000,  // 10 MB max file size
        allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp'], // Images only
    });

    console.log('Bucket created:', bucket.$id);
    return bucket;
}

createImageBucket();
```

## Step 2: Upload a File (Client-Side)

This runs in the browser using the `appwrite` Web SDK:

```typescript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// Client-side setup (user must be authenticated)
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);

const BUCKET_ID = '[BUCKET_ID]'; // The bucket ID from Step 1

/**
 * Upload an image file from an <input type="file"> element.
 * Sets file-level permissions so:
 *   - Anyone can view the image (public read)
 *   - Only the uploader can update or delete it
 */
async function uploadImage(userId: string): Promise<string> {
    const fileInput = document.getElementById('file-input') as HTMLInputElement;
    const selectedFile = fileInput.files?.[0];

    if (!selectedFile) {
        throw new Error('No file selected');
    }

    const file = await storage.createFile({
        bucketId: BUCKET_ID,
        fileId: ID.unique(),
        file: selectedFile,
        permissions: [
            Permission.read(Role.any()),              // Anyone can view the image
            Permission.update(Role.user(userId)),     // Only the uploader can update
            Permission.delete(Role.user(userId)),     // Only the uploader can delete
        ],
    });

    console.log('File uploaded:', file.$id);
    return file.$id;
}
```

## Step 3: Get a Preview URL for the Image

